// 400 CRCST certification exam questions
export const QUESTIONS: Question[] = [
  {id:'1',question:'Soiled instruments and other items are received in which area of the Sterile Processing department?',options:['Preparation','Packaging','Decontamination','Sterilization'],correct_answer:2,domain:'SPD Overview',difficulty:'easy',explanation:'Decontamination is the entry point for all soiled items in SPD — workflow always moves from soiled to clean.'},
  {id:'2',question:'The first step in the sterilization process is:',options:['Receiving','Sorting','Soaking','Cleaning'],correct_answer:3,domain:'Sterilization',difficulty:'easy',explanation:'Cleaning is always the first and most critical step — sterilization cannot succeed on soiled instruments.'},
  {id:'3',question:'To minimize exposure to bloodborne pathogens SP technicians must wear special attire referred to as:',options:['Personal protective equipment','Personal protection garments','Professional protective equipment','Personal safety attire'],correct_answer:0,domain:'Safety',difficulty:'easy',explanation:'PPE is the correct term per OSHA Bloodborne Pathogen Standard.'},
  {id:'4',question:'Instrument sets needed for all scheduled procedures for an entire day are usually pulled:',options:['Two days before','Day or evening before','Morning of surgery','Early morning day of'],correct_answer:1,domain:'Assembly',difficulty:'easy',explanation:'Case carts are typically pulled the day or evening before to allow time for verification and assembly.'},
  {id:'5',question:'Healthcare-associated infections (HAIs) are:',options:['Most likely to occur during a surgical procedure','Caused by drug-resistant organisms','Infections without known cures','Infections that occur on or after day three of a hospitalization'],correct_answer:3,domain:'Infection Prevention',difficulty:'medium',explanation:'HAIs are defined as infections occurring on or after the third day of a hospital stay.'},
  {id:'6',question:'SP workflow should move from:',options:['Clean to soiled','Unrestricted to semi-restricted','Soiled to clean','Clean to sterile'],correct_answer:2,domain:'SPD Overview',difficulty:'easy',explanation:'SPD workflow always moves from soiled to clean to prevent cross-contamination.'},
  {id:'7',question:'While items may be dispensed to all areas of a facility the major focus of the SPD is:',options:['The Emergency Department','Labor and Delivery','Supply Chain Management','The Operating Room'],correct_answer:3,domain:'SPD Overview',difficulty:'easy',explanation:'The OR is the primary customer of SPD — most instruments processed are for surgical procedures.'},
  {id:'8',question:'Working in the decontamination area requires:',options:['Knowledge of microbiology','Knowledge of cleaning and disinfecting processes','Instrument identification','All the above'],correct_answer:3,domain:'Decontamination',difficulty:'easy',explanation:'All three are required competencies for decontamination area technicians.'},
  {id:'9',question:'The suffix -itis means:',options:['Illness','Inflammation','The study of','Pain'],correct_answer:1,domain:'Medical Terminology',difficulty:'easy',explanation:'The suffix -itis means inflammation — e.g. appendicitis, arthritis.'},
  {id:'10',question:'The suffix -ectomy means:',options:['To repair','Surgical removal','Inflammation','To cut'],correct_answer:1,domain:'Medical Terminology',difficulty:'easy',explanation:'The suffix -ectomy means surgical removal — e.g. appendectomy, tonsillectomy.'},
  {id:'11',question:'The suffix -oscopy means:',options:['Visual examination','Disease','Surgical removal','Diagnosis of a condition'],correct_answer:0,domain:'Medical Terminology',difficulty:'easy',explanation:'The suffix -oscopy means visual examination — e.g. arthroscopy, laparoscopy.'},
  {id:'12',question:'The prefix hypo- means:',options:['Quickly','Above','Below','Measured'],correct_answer:2,domain:'Medical Terminology',difficulty:'easy',explanation:'Hypo- means below or under — e.g. hypoglycemia, hypotension.'},
  {id:'13',question:'Which of the following means beside or near?',options:['Para','Peri','Parta','Pana'],correct_answer:1,domain:'Medical Terminology',difficulty:'easy',explanation:'The prefix peri- means beside or near — e.g. perioperative, periosteal.'},
  {id:'14',question:'The suffix -tome means:',options:['Surgical restoration','Surgical fixation','To suture','Cutting instrument'],correct_answer:3,domain:'Medical Terminology',difficulty:'easy',explanation:'The suffix -tome means cutting instrument — e.g. osteotome, dermatome.'},
  {id:'15',question:'Arthroscopy means:',options:['Visual examination of a joint','Surgical replacement of a joint','Inflammation of a joint','Surgical removal of a joint'],correct_answer:0,domain:'Medical Terminology',difficulty:'easy',explanation:'Arthro = joint, -oscopy = visual examination.'},
  {id:'16',question:'The word laminectomy means:',options:['Removal of a cyst in the spine','Removal of part of the vertebrae in the spine','To insert rods into the spine','The study of the spine'],correct_answer:1,domain:'Medical Terminology',difficulty:'medium',explanation:'Lamin = lamina (part of vertebra), -ectomy = removal.'},
  {id:'17',question:'Which surgical abbreviation might be used relating to a fractured bone?',options:['CABG','BSO','ORIF','TAH'],correct_answer:2,domain:'Medical Terminology',difficulty:'medium',explanation:'ORIF = Open Reduction Internal Fixation — surgical repair of a fracture.'},
  {id:'18',question:'Lithotripsy means:',options:['Aspiration of fatty tissue','Surgical removal of ovary','Crushing of a stone','Visual examination of joint'],correct_answer:2,domain:'Medical Terminology',difficulty:'medium',explanation:'Litho = stone, -tripsy = crushing — used to break up kidney stones.'},
  {id:'19',question:'The system that gives the body shape and support is the:',options:['Muscular system','Nervous system','Skeletal system','Circulatory system'],correct_answer:2,domain:'Anatomy',difficulty:'easy',explanation:'The skeletal system provides the structural framework and support for the body.'},
  {id:'20',question:'The tissue that acts as a cushion between bones is:',options:['Tendon','Muscle','Cartilage','Ligament'],correct_answer:2,domain:'Anatomy',difficulty:'easy',explanation:'Cartilage acts as a cushion between bones preventing direct bone-on-bone contact.'},
  {id:'21',question:'The largest part of the human brain is the:',options:['Brain stem','Cerebellum','Cerebrum','Pituitary gland'],correct_answer:2,domain:'Anatomy',difficulty:'easy',explanation:'The cerebrum is the largest part of the brain controlling thought, memory, and voluntary movement.'},
  {id:'22',question:'This yellowish liquid makes up more than 55% of blood:',options:['Platelets','Red blood cells','White blood cells','Plasma'],correct_answer:3,domain:'Anatomy',difficulty:'easy',explanation:'Plasma is the liquid component of blood making up over 55% of blood volume.'},
  {id:'23',question:'The hip joint is an example of a:',options:['Gliding joint','Ball-and-socket joint','Pivot joint','Hinge joint'],correct_answer:1,domain:'Anatomy',difficulty:'easy',explanation:'The hip joint is a ball-and-socket joint allowing movement in multiple directions.'},
  {id:'24',question:'This tissue covers the body\'s external surface:',options:['Epithelial tissue','Connective tissue','Muscular tissue','Nervous tissue'],correct_answer:0,domain:'Anatomy',difficulty:'easy',explanation:'Epithelial tissue covers the body\'s external surface and lines internal organs and cavities.'},
  {id:'25',question:'Cartilage is replaced by bone through a process called:',options:['Ossification','Calcification','Osmosis','Cancellous formation'],correct_answer:0,domain:'Anatomy',difficulty:'medium',explanation:'Ossification is the process by which cartilage is replaced by bone during development.'},
  {id:'26',question:'Anaerobic bacteria are able to survive without:',options:['Oxygen','Warm soil','Temperatures above 100 degrees F','Water'],correct_answer:0,domain:'Microbiology',difficulty:'easy',explanation:'Anaerobic bacteria do not require oxygen to survive — they can grow in oxygen-free environments.'},
  {id:'27',question:'A spore is:',options:['The control unit of a cell','Located in the cell nucleus','Very difficult to kill','Very easy to kill'],correct_answer:2,domain:'Microbiology',difficulty:'medium',explanation:'Spores form a thick protective wall making them extremely resistant to heat, chemicals, and desiccation.'},
  {id:'28',question:'Staphylococcus is classified as a:',options:['Gram-positive bacteria','Gram-negative bacteria','Prion','Virus'],correct_answer:0,domain:'Microbiology',difficulty:'medium',explanation:'Staphylococcus is a gram-positive bacterium — it retains the crystal violet stain in gram staining.'},
  {id:'29',question:'Microorganisms that cause disease are called:',options:['Gram positive','Gram negative','Pathogens','Potentially infectious'],correct_answer:2,domain:'Microbiology',difficulty:'easy',explanation:'Pathogens are microorganisms capable of causing disease in a host.'},
  {id:'30',question:'The virus that causes hepatitis B is transmitted by:',options:['Contact','Blood','Airborne and droplet routes','Vectors'],correct_answer:1,domain:'Infection Prevention',difficulty:'medium',explanation:'Hepatitis B is transmitted through blood and blood-contaminated body fluids.'},
  {id:'31',question:'Jewelry should not be worn in SP work areas because it:',options:['Harbors microorganisms','Is expensive','May become damaged','May be misplaced or stolen'],correct_answer:0,domain:'Safety',difficulty:'easy',explanation:'Jewelry harbors microorganisms that cannot be effectively removed and poses an infection control risk.'},
  {id:'32',question:'During handwashing hands should be lathered and scrubbed for at least:',options:['10 seconds','20 seconds','1 minute','2 minutes'],correct_answer:1,domain:'Safety',difficulty:'easy',explanation:'CDC recommends lathering and scrubbing hands for at least 20 seconds.'},
  {id:'33',question:'To protect themselves from splashes SP technicians assigned to decontamination should wear:',options:['Double-cloth gowns','Blue surgical scrubs','Fluid-resistant gowns','Sterile OR gowns'],correct_answer:2,domain:'Safety',difficulty:'easy',explanation:'Fluid-resistant gowns protect against splashes and spills in the decontamination area.'},
  {id:'34',question:'The main theory of Standard Precautions is that patients:',options:['In high-risk categories may be infectious','Diagnosed with a specific disease may be infectious','Are generally healthy unless they show symptoms','Must all be treated as if their blood and bodily fluids are infectious'],correct_answer:3,domain:'Infection Prevention',difficulty:'easy',explanation:'Standard Precautions require treating all patients as potentially infectious regardless of diagnosis.'},
  {id:'35',question:'The color of biohazard containers labels and signs should be:',options:['Red/orange','Orange/yellow','Orange/blue','Green/black'],correct_answer:0,domain:'Safety',difficulty:'easy',explanation:'Biohazard containers, labels, and signs must be red or orange-red per OSHA requirements.'},
  {id:'36',question:'The decontamination area of the SPD should have:',options:['Negative airflow','Positive airflow','Filtered airflow','No air exchanges'],correct_answer:0,domain:'Safety',difficulty:'medium',explanation:'Negative airflow in decontamination contains contaminants and prevents them from escaping to clean areas.'},
  {id:'37',question:'The absence of microorganisms that cause disease is called:',options:['Infection prevention','Infection control','Asepsis','HAI control'],correct_answer:2,domain:'Infection Prevention',difficulty:'easy',explanation:'Asepsis is the absence of pathogenic microorganisms — the goal of sterile processing.'},
  {id:'38',question:'Chemical indicators are classified as:',options:['FDA Class I medical devices','FDA Class II medical devices','FDA Class III medical devices','Not regulated by the FDA'],correct_answer:1,domain:'Quality & Regulatory',difficulty:'hard',explanation:'Chemical indicators are classified as FDA Class II medical devices subject to premarket notification.'},
  {id:'39',question:'Standards and regulations help set the SPD\'s levels of:',options:['Quality','Safety','Efficiency','Both quality and safety'],correct_answer:3,domain:'Quality & Regulatory',difficulty:'easy',explanation:'Standards and regulations establish both quality and safety levels for SPD operations.'},
  {id:'40',question:'Medical device reporting is regulated by the:',options:['NFPA','EPA','WHO','FDA'],correct_answer:3,domain:'Quality & Regulatory',difficulty:'medium',explanation:'The FDA regulates medical device reporting through the MedWatch program and MDR regulations.'},
  {id:'41',question:'Formal training should occur:',options:['For new employees','At least monthly','For employees moving to a new position','For new employees and those moving to new positions'],correct_answer:3,domain:'Quality & Regulatory',difficulty:'easy',explanation:'Formal training is required both for new hires and for any employee transitioning to a new role.'},
  {id:'42',question:'Monitoring records must be:',options:['Accurate','Legible','Complete','All the above'],correct_answer:3,domain:'Quality & Regulatory',difficulty:'easy',explanation:'Monitoring records must be accurate, legible, and complete to be valid for regulatory purposes.'},
  {id:'43',question:'Sterilizer load records should contain:',options:['Items and quantities sterilized','Types of packaging used in each load','Preventive maintenance dates','All the above'],correct_answer:3,domain:'Sterilization',difficulty:'medium',explanation:'Sterilizer load records must document items sterilized, packaging types, and PM dates for full traceability.'},
  {id:'44',question:'External indicators show the item was exposed to a sterilization process but do NOT prove sterility was achieved:',options:['True','False','Only for steam processes','Only for EO processes'],correct_answer:0,domain:'Sterilization',difficulty:'medium',explanation:'External CIs show the item was exposed to sterilization conditions — they do not prove sterility was achieved.'},
  {id:'45',question:'Temperature and humidity levels in the SPD need to be monitored and recorded:',options:['Weekly preferably daily','For each shift','At least daily','At least monthly'],correct_answer:2,domain:'Quality & Regulatory',difficulty:'medium',explanation:'Temperature and humidity in the SPD must be monitored and recorded at least daily per AAMI standards.'},
  {id:'46',question:'A Class II chemical indicator cleared by the FDA and run daily in dynamic air removal sterilizers is called a/an:',options:['Process challenge device','External CI','Biological indicator','Bowie-Dick test'],correct_answer:3,domain:'Sterilization',difficulty:'hard',explanation:'The Bowie-Dick test is a Class II chemical indicator run daily in dynamic air removal sterilizers to check air removal.'},
  {id:'47',question:'A positive biological indicator (BI) means:',options:['The incubation process is complete','There is no growth in the ampule after incubation','There is growth in the ampule after incubation','None of the above'],correct_answer:2,domain:'Sterilization',difficulty:'medium',explanation:'A positive BI shows growth in the ampule after incubation — meaning sterilization failed.'},
  {id:'48',question:'Failure mode and effects analysis (FMEA) tries to predict:',options:['The amount of wasted effort in a day','The cause of a sentinel event','A product failure before it occurs','All the above'],correct_answer:2,domain:'Quality & Regulatory',difficulty:'hard',explanation:'FMEA is a proactive tool that identifies potential failures before they occur.'},
  {id:'49',question:'Root cause analysis (RCA):',options:['Is proactive','Is a method of identifying problems before they occur','Focuses on properly educating staff about quality measures','Looks at a poor outcome to prevent its reoccurrence'],correct_answer:3,domain:'Quality & Regulatory',difficulty:'medium',explanation:'RCA is reactive — it examines a poor outcome after it occurs to identify root causes and prevent recurrence.'},
  {id:'50',question:'This component of a quality program moves decision making to frontline staff:',options:['Quality monitoring','Empowerment','Process management','All the above'],correct_answer:1,domain:'Quality & Regulatory',difficulty:'medium',explanation:'Empowerment is the quality program component that moves decision making authority to frontline staff.'},
  {id:'51',question:'Which system provides supplies and instruments for individual surgical procedures?',options:['Exchange cart','PAR','Case cart','Requisition'],correct_answer:2,domain:'Inventory & Distribution',difficulty:'easy',explanation:'The case cart system provides all supplies and instruments needed for individual surgical procedures.'},
  {id:'52',question:'The inventory system that stocks supplies by pre-established stock levels is called a/an:',options:['PAR system','Case cart system','Fulfillment system','Exchange system'],correct_answer:0,domain:'Inventory & Distribution',difficulty:'medium',explanation:'The PAR (Periodic Automatic Replenishment) system maintains stock at pre-established levels.'},
  {id:'53',question:'The inventory system that uses two identical carts to facilitate supply replenishment is called the:',options:['Case cart system','Exchange cart system','PAR system','Requisition system'],correct_answer:1,domain:'Inventory & Distribution',difficulty:'medium',explanation:'The exchange cart system uses two identical carts — one in use while the other is being restocked.'},
  {id:'54',question:'All patient care equipment that was dispensed for use must be considered:',options:['Sterile','Clean','Contaminated','Visibly soiled'],correct_answer:2,domain:'Equipment',difficulty:'easy',explanation:'All patient care equipment returned after use must be considered contaminated regardless of appearance.'},
  {id:'55',question:'Preventive maintenance (PM) is:',options:['Performed when a piece of equipment injures a patient','Designed to identify potential problems before they occur','Performed when a user unit notices a problem','Completed by SP before equipment is dispensed'],correct_answer:1,domain:'Equipment',difficulty:'easy',explanation:'Preventive maintenance is designed to identify and address potential problems before they occur.'},
  {id:'56',question:'Which tracking method provides real-time information?',options:['RFID tags','Laser-etched barcodes','Standard barcodes','Dot matrix applications'],correct_answer:0,domain:'Information Technology',difficulty:'medium',explanation:'RFID tags provide real-time location and status information automatically.'},
  {id:'57',question:'Safety data sheets (SDSs) are provided by:',options:['OSHA','FDA','The Risk Management department','The product manufacturer'],correct_answer:3,domain:'Safety',difficulty:'easy',explanation:'Safety Data Sheets are provided by the product manufacturer.'},
  {id:'58',question:'The process of changing work or working conditions to reduce physical stress is called:',options:['Ergonomics','An employee injury reduction plan','OSHA\'s Workers\' Rights Program','OSHA\'s Risk Management Program'],correct_answer:0,domain:'Safety',difficulty:'easy',explanation:'Ergonomics is the science of changing work or working conditions to reduce physical stress.'},
  {id:'59',question:'Time-weighted average (TWA) is:',options:['A test to reduce ergonomic stress','Measure of hazardous chemicals in a department','The amount of a substance a person can be exposed to over an eight-hour period','Measure of smoke remaining after a fire'],correct_answer:2,domain:'Safety',difficulty:'hard',explanation:'TWA is the amount of a hazardous substance a person can be exposed to averaged over an 8-hour work period.'},
  {id:'60',question:'Which of the following is required for sharps safety?',options:['Disposing all single-use sharps in an appropriate container','Pointing sharp ends away from any part of one\'s body during transport','Not blindly reaching into an instrument tray','All the above'],correct_answer:3,domain:'Safety',difficulty:'easy',explanation:'All three are required sharps safety practices to prevent needlestick and sharps injuries.'},
  {id:'61',question:'Which of the following is the most important factor for effective teamwork?',options:['Attitude','Promptness','Loyalty','Cooperation'],correct_answer:3,domain:'Professional Development',difficulty:'medium',explanation:'Cooperation is the most important factor for effective teamwork.'},
  {id:'62',question:'A group of employees from different departments that works together to resolve operating problems is called a:',options:['Decision-making team','Multi-dimensional team','Cross-functional team','Management team'],correct_answer:2,domain:'Professional Development',difficulty:'easy',explanation:'A cross-functional team consists of employees from different departments working together.'},
  {id:'63',question:'Coaching is an example of:',options:['Informal communication','Discipline','Formal communication','Mentoring'],correct_answer:3,domain:'Professional Development',difficulty:'medium',explanation:'Coaching is a form of mentoring — providing guidance and support to help someone develop professionally.'},
  {id:'64',question:'Personal development:',options:['Improves employability','Expands personal potential','Is a lifelong process','All the above'],correct_answer:3,domain:'Professional Development',difficulty:'easy',explanation:'Personal development improves employability, expands potential, and is a continuous lifelong process.'},
  {id:'65',question:'Steps toward attaining professional goals in SP include:',options:['Obtaining certification','Attending educational conferences','Participating in professional groups','All the above'],correct_answer:3,domain:'Professional Development',difficulty:'easy',explanation:'All three are important steps — certification, conferences, and professional group participation.'},
  {id:'66',question:'This agency may intervene in a matter of worker protection even if there are no specific regulations covering the situation:',options:['OSHA','EPA','FDA','AORN'],correct_answer:0,domain:'Quality & Regulatory',difficulty:'medium',explanation:'OSHA has broad authority to intervene in worker protection matters even without specific regulations.'},
  {id:'67',question:'This agency imposes very strict labeling requirements on manufacturers of disinfectants used by SPDs:',options:['OSHA','FDA','EPA','AAMI'],correct_answer:2,domain:'Quality & Regulatory',difficulty:'hard',explanation:'The EPA imposes strict labeling requirements on disinfectants and sterilants used in healthcare.'},
  {id:'68',question:'Heart valves and pacemakers are examples of:',options:['FDA Class I medical devices','FDA Class II medical devices','FDA Class III medical devices','None of the above'],correct_answer:2,domain:'Quality & Regulatory',difficulty:'hard',explanation:'High-risk implantable devices like heart valves and pacemakers are FDA Class III.'},
  {id:'69',question:'Under current regulations who is required to report suspected medical device-related deaths to the FDA?',options:['Device manufacturers','Healthcare facilities','Both of the above','None of the above'],correct_answer:2,domain:'Quality & Regulatory',difficulty:'hard',explanation:'Both device manufacturers and healthcare facilities are required to report suspected device-related deaths.'},
  {id:'70',question:'The only way to interrupt the transmission of a causative agent is to:',options:['Sterilize the item','Wear appropriate PPE','Eliminate it','Involve OSHA'],correct_answer:2,domain:'Infection Prevention',difficulty:'medium',explanation:'Eliminating the causative agent is the only definitive way to interrupt disease transmission.'},
  {id:'71',question:'Departmental dress codes apply to:',options:['Everyone entering the SPD','Only hospital employees','Only people spending more than 10 minutes','Only visitors and maintenance personnel'],correct_answer:0,domain:'Safety',difficulty:'easy',explanation:'Dress codes apply to everyone entering the SPD including visitors, vendors, and maintenance personnel.'},
  {id:'72',question:'Inanimate objects that can transmit bacteria are called:',options:['Transmission devices','Fomites','Carriers','Superspreaders'],correct_answer:1,domain:'Microbiology',difficulty:'medium',explanation:'Fomites are inanimate objects that can harbor and transmit microorganisms.'},
  {id:'73',question:'Floors in the SPD should be:',options:['Wet mopped daily','Wet mopped weekly','Swept daily and wet mopped weekly','Swept daily'],correct_answer:0,domain:'Safety',difficulty:'easy',explanation:'SPD floors should be wet mopped daily — sweeping and dust mopping spread microorganisms.'},
  {id:'74',question:'Know what is dirty know what is clean know what is sterile — these are known as the:',options:['Principles of asepsis','Basics of the Bloodborne Pathogen Standard','Principles of infection prevention and control','Basics of environmental control'],correct_answer:2,domain:'Infection Prevention',difficulty:'medium',explanation:'These are the principles of infection prevention and control that guide SPD workflow.'},
  {id:'75',question:'Which traffic control requirement applies to the clean assembly area of the SPD?',options:['Biohazard','Unrestricted','Semi-restricted','Restricted'],correct_answer:2,domain:'SPD Overview',difficulty:'medium',explanation:'The clean assembly area is semi-restricted — limited access with appropriate dress code required.'},
  {id:'76',question:'Temperature and humidity parameters can best be established by reviewing which document?',options:['ANSI/AAMI ST79','OSHA 29 CFR 1910.1030','ANSI/ASHRAE/ASHE 170','ANSI/AAMI ST91'],correct_answer:2,domain:'Quality & Regulatory',difficulty:'hard',explanation:'ANSI/ASHRAE/ASHE 170 establishes ventilation and environmental requirements for healthcare facilities.'},
  {id:'77',question:'Viruses are:',options:['Larger than bacteria','Smaller than bacteria','Gram-positive microorganisms','Gram-negative microorganisms'],correct_answer:1,domain:'Microbiology',difficulty:'easy',explanation:'Viruses are much smaller than bacteria and cannot replicate outside a living host cell.'},
  {id:'78',question:'Microorganisms reproduce by a process called:',options:['Repopulation','Binary fission','Replication','Bilateral reproduction'],correct_answer:1,domain:'Microbiology',difficulty:'easy',explanation:'Binary fission is the primary reproductive process — one cell splits into two identical daughter cells.'},
  {id:'79',question:'Which hepatitis virus is said to be the most prevalent chronic bloodborne infection today?',options:['Hepatitis A','Hepatitis B','Hepatitis C','Hepatitis D'],correct_answer:2,domain:'Infection Prevention',difficulty:'hard',explanation:'Hepatitis C is the most common chronic bloodborne infection in the United States.'},
  {id:'80',question:'Which is an example of a fungus?',options:['Pneumonia','Tuberculosis','Athlete\'s foot','Herpes simplex'],correct_answer:2,domain:'Microbiology',difficulty:'medium',explanation:'Athlete\'s foot is caused by a fungus. Pneumonia and TB are bacterial, herpes is viral.'},
  {id:'81',question:'The term septorhinoplasty means:',options:['Surgery of a muscle wound','Surgical repair of the nose','Removal of a cyst','Incision into the stomach'],correct_answer:1,domain:'Medical Terminology',difficulty:'medium',explanation:'Septo = septum, rhino = nose, -plasty = surgical repair.'},
  {id:'82',question:'Encephalopathy is a/an:',options:['Disease of the brain','Inflammation of the liver','Fluid-filled sack','Inflammation of a joint'],correct_answer:0,domain:'Medical Terminology',difficulty:'medium',explanation:'Encephalo = brain, -pathy = disease.'},
  {id:'83',question:'This organ filters the blood to remove amino acids and neutralize some harmful toxins:',options:['Kidney','Pancreas','Liver','Gallbladder'],correct_answer:2,domain:'Anatomy',difficulty:'medium',explanation:'The liver filters blood to remove amino acids and neutralize harmful toxins.'},
  {id:'84',question:'This surgical procedure removes the uterus:',options:['Hysteroscopy','Hysterectomy','Dilation and curettage','Bilateral salpingo-oophorectomy'],correct_answer:1,domain:'Medical Terminology',difficulty:'easy',explanation:'Hysterectomy = surgical removal of the uterus. Hyster = uterus, -ectomy = removal.'},
  {id:'85',question:'This gland stimulates body growth:',options:['Adrenal','Thyroid','Pancreas','Pituitary'],correct_answer:3,domain:'Anatomy',difficulty:'medium',explanation:'The pituitary gland stimulates body growth and controls other endocrine glands.'},
  {id:'86',question:'This surgical procedure removes tissue or displaced bone from the wrist to release pressure on the median nerve:',options:['Carpal tunnel repair','Ulnar nerve transposition','Arthrotomy','Fasciotomy'],correct_answer:0,domain:'Medical Terminology',difficulty:'medium',explanation:'Carpal tunnel release removes tissue or bone pressing on the median nerve in the wrist.'},
  {id:'87',question:'The end of a body part closest to the point of origin is called the:',options:['Lateral','Distal','Proximal','Medial'],correct_answer:2,domain:'Anatomy',difficulty:'medium',explanation:'Proximal means closest to the point of origin or the operator — distal is farthest away.'},
  {id:'88',question:'The throat is also called the:',options:['Esophagus','Larynx','Trachea','Pharynx'],correct_answer:3,domain:'Anatomy',difficulty:'easy',explanation:'The pharynx is the throat — it connects the nasal cavity and mouth to the larynx and esophagus.'},
  {id:'89',question:'This surgical procedure removes the gallbladder:',options:['Cholecystectomy','Colectomy','Parotidectomy','Gastrectomy'],correct_answer:0,domain:'Medical Terminology',difficulty:'easy',explanation:'Cholecystectomy = surgical removal of the gallbladder. Chole = bile/gallbladder, -ectomy = removal.'},
  {id:'90',question:'The white portion of the eye is called the:',options:['Retina','Iris','Pupil','Sclera'],correct_answer:3,domain:'Anatomy',difficulty:'easy',explanation:'The sclera is the white outer layer of the eye providing structure and protection.'},
  {id:'91',question:'Which of the following is the brain center of a cell?',options:['Cell membrane','Cytoplasm','Nucleus','Deoxyribonucleic acid'],correct_answer:2,domain:'Microbiology',difficulty:'easy',explanation:'The nucleus is the control center of the cell governing activity and heredity.'},
  {id:'92',question:'This is referred to as the voice box:',options:['Pharynx','Larynx','Mouth','Trachea'],correct_answer:1,domain:'Anatomy',difficulty:'easy',explanation:'The larynx is the voice box containing the vocal cords.'},
  {id:'93',question:'Which percentage of bacteria is not harmful to humans?',options:['75%','80%','90%','95%'],correct_answer:2,domain:'Microbiology',difficulty:'medium',explanation:'Approximately 90% of bacteria are not harmful — only a small percentage are pathogenic.'},
  {id:'94',question:'The measure of alkalinity or acidity refers to:',options:['Temperature','pH','Moisture','Humidity'],correct_answer:1,domain:'Decontamination',difficulty:'easy',explanation:'pH measures the acidity or alkalinity of a solution on a scale of 0-14.'},
  {id:'95',question:'Which of the following is not a gram-positive bacteria?',options:['Geobacillus','Escherichia coli','Klebsiella','Pseudomonas'],correct_answer:1,domain:'Microbiology',difficulty:'hard',explanation:'Escherichia coli is gram-negative. Geobacillus is gram-positive.'},
  {id:'96',question:'Which is not a common bacterial shape?',options:['Spherical','Cylindrical','Rod','Spiral'],correct_answer:1,domain:'Microbiology',difficulty:'medium',explanation:'Cylindrical is not a standard bacterial shape. The three shapes are spherical, rod, and spiral.'},
  {id:'97',question:'The functional center of a cell is the:',options:['Cytoplasm','Nucleus','Cell membrane','Capsule'],correct_answer:1,domain:'Microbiology',difficulty:'easy',explanation:'The nucleus is the functional center governing cell activity and containing genetic material.'},
  {id:'98',question:'Quality control indicators:',options:['Include RCA and FMEA','Are used to determine how well the department is meeting its objectives','Should be monitored periodically','All the above'],correct_answer:3,domain:'Quality & Regulatory',difficulty:'medium',explanation:'Quality control indicators include all of these functions.'},
  {id:'99',question:'When quality is not emphasized:',options:['FMEA and RCA will not work','A cross-functional team should be created','Conflicts can arise','All the above'],correct_answer:3,domain:'Quality & Regulatory',difficulty:'medium',explanation:'All three consequences occur when quality is not emphasized.'},
  {id:'100',question:'The movement of supplies throughout the healthcare facility is called:',options:['Distribution','Inventory management','Case cart system','Procurement'],correct_answer:0,domain:'Inventory & Distribution',difficulty:'easy',explanation:'Distribution is the process of moving supplies and instruments throughout the healthcare facility.'},
  {id:'101',question:'Automated supply replenishment systems are:',options:['No longer used','Used only in surgery','Difficult to manage','Computerized'],correct_answer:3,domain:'Inventory & Distribution',difficulty:'easy',explanation:'Automated supply replenishment systems are computerized and track usage to automatically reorder supplies.'},
  {id:'102',question:'Items like disposable wraps are called:',options:['Consumable supplies','Capital supplies','Patient care supplies','Non-refundable supplies'],correct_answer:0,domain:'Inventory & Distribution',difficulty:'easy',explanation:'Consumable supplies are items that are used once and discarded.'},
  {id:'103',question:'Capital equipment items are:',options:['Usually used for patient care','Items with a lower purchase price','Items with a higher purchase price','Purchased stored consumed and reordered'],correct_answer:2,domain:'Inventory & Distribution',difficulty:'easy',explanation:'Capital equipment items have a higher purchase price and are durable.'},
  {id:'104',question:'The wave/do not reuse symbol on a device means:',options:['Product lot number','Use by date','Single-use item do not reuse','Date of manufacture'],correct_answer:2,domain:'Quality & Regulatory',difficulty:'medium',explanation:'The wave symbol indicates the item is a single-use device and must not be reprocessed.'},
  {id:'105',question:'The hourglass symbol on a device means:',options:['Product lot number','Use by date','Single-use item do not reuse','Date of manufacture'],correct_answer:1,domain:'Quality & Regulatory',difficulty:'medium',explanation:'The hourglass symbol indicates the use by date — the expiration date of the item.'},
  {id:'106',question:'Technicians in this department perform safety inspections and functional tests on equipment:',options:['Supply Chain Management','Infection Prevention and Control','Biomedical/Clinical Engineering','Facilities Maintenance'],correct_answer:2,domain:'Equipment',difficulty:'easy',explanation:'Biomedical/Clinical Engineering technicians perform safety inspections and functional testing on patient care equipment.'},
  {id:'107',question:'When patient equipment enters a healthcare facility it must be safety checked by a/an before it is cleared for patient use:',options:['Biomedical technician','Infection Prevention committee member','SP technician','SP director'],correct_answer:0,domain:'Equipment',difficulty:'easy',explanation:'A biomedical technician must safety check all patient equipment before it is cleared for patient use.'},
  {id:'108',question:'Which requires that preventive maintenance standards be established for medical equipment?',options:['OSHA','The Joint Commission','AAMI','NIOSH'],correct_answer:1,domain:'Quality & Regulatory',difficulty:'medium',explanation:'The Joint Commission requires that preventive maintenance standards be established and followed.'},
  {id:'109',question:'Which of the following is not a consideration when recording patient care equipment?',options:['Equipment location','PM history','Patient diagnosis','Repair history'],correct_answer:2,domain:'Equipment',difficulty:'medium',explanation:'Patient diagnosis is not a consideration when recording and maintaining patient care equipment records.'},
  {id:'110',question:'Disposable components such as pads and tubing on patient care equipment should be:',options:['Discarded at the point of use','Reprocessed for reuse','Discarded during PM','Removed in the Biomedical Engineering department'],correct_answer:0,domain:'Equipment',difficulty:'easy',explanation:'Disposable components must be discarded at the point of use — they cannot be reused.'},
  {id:'111',question:'Equipment should be inspected for obvious hazards such as cracked or frayed electrical cords:',options:['Only by trained Biomedical Engineering technicians','Only during PM activities','Only when there are complaints from user departments','Whenever the equipment is inspected in SP'],correct_answer:3,domain:'Equipment',difficulty:'medium',explanation:'Any SP staff member who inspects equipment should check for obvious hazards at that time.'},
  {id:'112',question:'If an equipment malfunction causes patient harm it should be:',options:['Discarded immediately','Sent to the manufacturer for repairs','Sequestered for inspection by OSHA personnel','Returned immediately to the Biomedical Engineering department'],correct_answer:3,domain:'Equipment',difficulty:'medium',explanation:'Equipment causing patient harm must be sequestered and returned immediately to Biomedical Engineering.'},
  {id:'113',question:'Patient care equipment should be stored in a condition that is:',options:['Ready to dispense','Ready to clean','Ready to inspect','Ready to sterilize'],correct_answer:0,domain:'Equipment',difficulty:'easy',explanation:'Patient care equipment should be stored in a ready-to-dispense condition.'},
  {id:'114',question:'When transporting soiled medical equipment:',options:['Use an open case cart','Choose a route that minimizes contact with patients','Using PPE including gloves is optional','Perform hand hygiene only when hands are soiled'],correct_answer:1,domain:'Safety',difficulty:'easy',explanation:'Choose a transport route that minimizes contact with patients and visitors.'},
  {id:'115',question:'Which statement is correct regarding patient care equipment tracking?',options:['Patient care equipment tracking requires a computer','Equipment should only be tracked if it has a value exceeding facility specifications','Tracking patient care equipment can prevent equipment shortages','Equipment must only be tracked if its usage will be charged to patients'],correct_answer:2,domain:'Equipment',difficulty:'medium',explanation:'Tracking patient care equipment prevents shortages by knowing where equipment is located at all times.'},
  {id:'116',question:'The decision to use reusable or disposable instruments in procedure trays is determined by:',options:['Where the instruments will be used','The Infection Prevention and Control department','Several factors including physician preference storage and cost','The number of items to be used and the delivery schedule'],correct_answer:2,domain:'Equipment',difficulty:'medium',explanation:'The decision involves multiple factors — physician preference, storage considerations, and cost analysis.'},
  {id:'117',question:'In addition to financial and operational management information technology systems are used to:',options:['Support patient safety','Track changes in standards','Track patient movement','All the above'],correct_answer:3,domain:'Information Technology',difficulty:'easy',explanation:'IT systems support patient safety, track standards changes, and track patient movement.'},
  {id:'118',question:'Information technology is used to:',options:['Track clinical information','Demonstrate quality of care','Provide decision support systems','All the above'],correct_answer:3,domain:'Information Technology',difficulty:'easy',explanation:'IT is used for clinical tracking, quality demonstration, and decision support.'},
  {id:'119',question:'Which of the following is not a result of computer integration?',options:['Elimination of redundant entry of information','Increased efficiency','Automatic critical updates to industry standards','Reduction of inaccurate and conflicting information'],correct_answer:2,domain:'Information Technology',difficulty:'medium',explanation:'Computer integration does not automatically update industry standards — standards require manual review.'},
  {id:'120',question:'Patient census information used in SP is obtained from the:',options:['Electronic medical record','Admissions and registration system','Financial system','Centralized patient order entry system'],correct_answer:1,domain:'Information Technology',difficulty:'medium',explanation:'Patient census information used in SP is obtained from the admissions and registration system.'},
  {id:'121',question:'Tracking individual instruments is important:',options:['To locate missing instruments','To locate the current location of instrument sets','For keeping instruments in a specific set','All the above'],correct_answer:3,domain:'Information Technology',difficulty:'easy',explanation:'All three are important reasons for tracking individual instruments.'},
  {id:'122',question:'Point-of-use computing:',options:['Is impossible in SP because of infection control requirements','Provides no benefit to the SPD','Moves computers into SP work areas','Eliminates data entry jobs'],correct_answer:2,domain:'Information Technology',difficulty:'medium',explanation:'Point-of-use computing moves computer terminals into SP work areas allowing real-time data entry.'},
  {id:'123',question:'Which of the following is not provided by an instrument tracking system?',options:['Productivity information','Financial data','Quality assurance data','Product updates and recall information'],correct_answer:1,domain:'Information Technology',difficulty:'medium',explanation:'Instrument tracking systems do not provide financial data.'},
  {id:'124',question:'Physical safety hazards may be caused by:',options:['Solutions used in the decontamination area','The environment','Splashing chemicals','Infectious waste'],correct_answer:3,domain:'Safety',difficulty:'medium',explanation:'Infectious waste is the primary physical safety hazard category encompassing all listed sources.'},
  {id:'125',question:'Which of the following is not a component of risk management?',options:['Injury prevention','Claims management','Staff management','Risk assessment'],correct_answer:2,domain:'Quality & Regulatory',difficulty:'medium',explanation:'Staff management is an HR function — the components of risk management are injury prevention, claims management, and risk assessment.'},
  {id:'126',question:'Which is not one of the three general occupational hazards found in the SPD?',options:['Physical hazards','Ergonomic hazards','Biological hazards','Chemical hazards'],correct_answer:2,domain:'Safety',difficulty:'hard',explanation:'The three general occupational hazards in SPD are physical, ergonomic, and chemical.'},
  {id:'127',question:'Information about chemical or hazardous substances must be available to:',options:['The SP departmental supervisor','Employees working in the decontamination area','Staff assigned to low-temperature sterilization','All staff'],correct_answer:3,domain:'Safety',difficulty:'easy',explanation:'Information about chemical and hazardous substances must be available to all staff.'},
  {id:'128',question:'Healthcare facilities are required by this organization to provide adequate ventilation systems PPE and safe work operating procedures:',options:['EPA','FDA','OSHA','CMS'],correct_answer:2,domain:'Quality & Regulatory',difficulty:'easy',explanation:'OSHA requires healthcare facilities to provide adequate ventilation systems, PPE, and safe work operating procedures.'},
  {id:'129',question:'To reduce the risk of slips and falls:',options:['Enforce the use of non-skid footwear in the SPD','Park mobile equipment in the main hallway outside the SPD','Check each cart\'s weight before moving it from an elevator','Always use transport carts'],correct_answer:0,domain:'Safety',difficulty:'easy',explanation:'Enforcing the use of non-skid footwear is the primary method to reduce slip and fall risk.'},
  {id:'130',question:'When a technician cannot see what is in a sink or basin they should:',options:['Drain the sink or basin','Wear heavy duty gloves to grasp objects in the sink','Have someone help determine what is in the sink or basin','All the above'],correct_answer:0,domain:'Safety',difficulty:'medium',explanation:'When unable to see into a sink or basin drain it first — never blindly reach in even with gloves.'},
  {id:'131',question:'This is the level of exposure to a harmful substance at which an employer must take required precautions:',options:['Time-weighted average (TWA)','Short-term exposure limit (STEL)','Permissible exposure limit (PEL)','Action level (AL)'],correct_answer:2,domain:'Safety',difficulty:'hard',explanation:'The Permissible Exposure Limit (PEL) is the level at which employers must take required precautions to protect workers.'},
  {id:'132',question:'Ergonomic injuries:',options:['Are not a concern for SP employees','Are rare in today\'s work environment','Are a risk factor for people who perform repetitive activities or physical work','Occur only in the office setting'],correct_answer:2,domain:'Safety',difficulty:'easy',explanation:'Ergonomic injuries are a significant risk for SP employees who perform repetitive activities.'},
  {id:'133',question:'Secondary containers for chemicals must be labeled with:',options:['A copy of the original manufacturer\'s label or a generic label identifying the chemical hazard warnings and directions','A permanent marker and state the chemical\'s name and designated storage location','Nothing — they are not allowed in healthcare facilities','No restrictions for container labels at this time'],correct_answer:0,domain:'Safety',difficulty:'medium',explanation:'Secondary containers must be labeled with either the original manufacturer label or a generic label identifying the chemical, hazard warnings, and directions.'},
  {id:'134',question:'A molecular reaction that creates an uncontrolled release of energy is called:',options:['Combustion','Polymerization','Vapor density','Fire'],correct_answer:1,domain:'Safety',difficulty:'hard',explanation:'Polymerization is the molecular reaction that creates an uncontrolled release of energy.'},
  {id:'135',question:'Which of the following is an example of communication?',options:['Spoken word','Written word','Non-verbal expressions','All the above'],correct_answer:3,domain:'Professional Development',difficulty:'easy',explanation:'Communication includes spoken words, written words, and non-verbal expressions.'},
  {id:'136',question:'This is an example of informal communication:',options:['Departmental bulletins and memos','Meeting discussions','Spreading rumors','Posting work schedules'],correct_answer:2,domain:'Professional Development',difficulty:'medium',explanation:'Spreading rumors is informal communication — bulletins, meeting discussions, and schedules are formal communication channels.'},
  {id:'137',question:'Behavior relating to what is right and wrong relative to the standards of professional conduct is called:',options:['Ethical behavior','Moral behavior','Legal behavior','Personal behavior'],correct_answer:0,domain:'Professional Development',difficulty:'easy',explanation:'Ethical behavior is behavior relating to what is right and wrong relative to standards of professional conduct.'},
  {id:'138',question:'When a listener asks a question during a conversation it is called:',options:['Stereotyping','Feedback','Communication looping','Halo interpretation'],correct_answer:1,domain:'Professional Development',difficulty:'easy',explanation:'When a listener asks a question it is called feedback — it confirms understanding.'},
  {id:'139',question:'This process allows a person to understand someone else\'s needs:',options:['Communication','Human relations','Feedback','Moral behavior'],correct_answer:1,domain:'Professional Development',difficulty:'medium',explanation:'Human relations is the process that allows a person to understand and respond to someone else\'s needs.'},
  {id:'140',question:'When speaking one should:',options:['Be influenced by the listener\'s emotions','Concentrate on the listener rather than oneself','Concentrate on oneself rather than the listener','Use technical jargon to address the listener'],correct_answer:1,domain:'Professional Development',difficulty:'easy',explanation:'Effective speaking requires concentrating on the listener\'s needs rather than the speaker\'s own thoughts.'},
  {id:'141',question:'Informal work groups frequently develop:',options:['An attitude that is detrimental to the organization','An informal communication system called the grapevine','A task group as an example of an informal group','A rule that employees can only be in one formal group'],correct_answer:1,domain:'Professional Development',difficulty:'medium',explanation:'Informal work groups frequently develop an informal communication system called the grapevine.'},
  {id:'142',question:'Valuing efforts to promote diversity can:',options:['Improve job satisfaction and decrease absenteeism','Create a culture of respect and promote teamwork','Increase creative thinking and problem solving','All the above'],correct_answer:3,domain:'Professional Development',difficulty:'easy',explanation:'Valuing diversity promotes all of these outcomes.'},
  {id:'143',question:'Knowing what is expected and consistently meeting those expectations is part of:',options:['Effective communication','Ethical behavior','Job success','Professional behavior'],correct_answer:3,domain:'Professional Development',difficulty:'easy',explanation:'Knowing expectations and consistently meeting them is the definition of professional behavior.'},
  {id:'144',question:'When SP technicians have internet access at work:',options:['It should be used for work-related purposes only','It may be used for any purpose as long as it does not interfere with work','It should only be used during break time','Employees should use their own discretion'],correct_answer:0,domain:'Professional Development',difficulty:'easy',explanation:'Internet access at work should be used for work-related purposes only.'},
  {id:'145',question:'Which of the following is an open-ended question?',options:['How long have you worked here?','Do you have experience with orthopedic instruments?','What problems do you most frequently encounter on the job?','What is the name of the SP director?'],correct_answer:2,domain:'Professional Development',difficulty:'easy',explanation:'An open-ended question requires more than a yes/no answer — it invites explanation and discussion.'},
  {id:'146',question:'When establishing personal goals set goals that are:',options:['Quickly attainable','Attainable within five years then set new goals','Attainable then build on those successes','Specific to one\'s current position and education'],correct_answer:2,domain:'Professional Development',difficulty:'medium',explanation:'Goals should be attainable and then build on successes — creating momentum for continued development.'},
  {id:'147',question:'Professional development includes:',options:['Keeping current in an existing job','Activities to advance skills','Attending on-the-job training and continuing education sessions','All the above'],correct_answer:3,domain:'Professional Development',difficulty:'easy',explanation:'Professional development encompasses all activities that improve skills and knowledge.'},
  {id:'148',question:'Mentoring others:',options:['Is only done by management personnel','Is a requirement for promotion','Requires one to be skilled in all areas of the department','Is a positive behavior that gets noticed'],correct_answer:3,domain:'Professional Development',difficulty:'easy',explanation:'Mentoring others is a positive behavior that gets noticed by leadership.'},
  {id:'149',question:'When developing a professional timeline one must:',options:['Recognize that some goals are easier to achieve than others','Realize that promotions do not usually happen overnight','Understand that things will not always go as planned','All the above'],correct_answer:3,domain:'Professional Development',difficulty:'easy',explanation:'All three are important realities when developing a professional timeline.'},
  {id:'150',question:'Online resources:',options:['Have been determined as reliable','Are always the best way to obtain information','Must be checked to confirm that the information and source are valid and current','Are always approved by the device manufacturer'],correct_answer:2,domain:'Professional Development',difficulty:'easy',explanation:'Online resources must always be verified for validity and currency.'},
  {id:'151',question:'One important step in preparing for an interview is:',options:['Reviewing the certification exam questions','Developing a written response to application questions','Anticipating possible interview questions','All the above'],correct_answer:3,domain:'Professional Development',difficulty:'medium',explanation:'All three are important interview preparation steps.'},
  {id:'152',question:'When a technician is promoted to a higher position:',options:['Their departmental relationships will change','They need to consider the broader needs of the department and facility','They should remember that things do not always go as planned','All the above'],correct_answer:3,domain:'Professional Development',difficulty:'easy',explanation:'All three are true when promoted — relationships change, perspective must broaden, and flexibility is required.'},
  {id:'153',question:'One type of formal monitoring is:',options:['Monitoring the department\'s temperature and humidity levels','Ensuring everyone entering the department is dressed appropriately','Ensuring everyone who enters practices good hand hygiene','Ensuring traffic protocols are followed'],correct_answer:0,domain:'Quality & Regulatory',difficulty:'medium',explanation:'Monitoring and recording temperature and humidity levels is formal monitoring — the others are informal.'},
  {id:'154',question:'A physical monitor on a washer-disinfector is the:',options:['Thermostatic valve','Printout','Biological test','All the above'],correct_answer:1,domain:'Decontamination',difficulty:'medium',explanation:'The printout is the physical monitor on a washer-disinfector showing time, temperature, and cycle data.'},
  {id:'155',question:'Cart washer floor screens should be checked:',options:['At least daily','During each shift','Weekly preferably daily','Monthly'],correct_answer:0,domain:'Equipment',difficulty:'easy',explanation:'Cart washer floor screens should be checked at least daily to prevent clogging.'},
  {id:'156',question:'Providing quality products directly impacts a patient\'s:',options:['Health','Outcome','Safety','All the above'],correct_answer:3,domain:'Quality & Regulatory',difficulty:'easy',explanation:'Quality products directly impact patient health, outcomes, and safety.'},
  {id:'157',question:'Quality monitoring is:',options:['The process of maintaining or improving quality outputs','A quick quality fix','Finding solutions to eliminate a root cause','Collecting standard data'],correct_answer:0,domain:'Quality & Regulatory',difficulty:'easy',explanation:'Quality monitoring is the ongoing process of maintaining and improving quality outputs.'},
  {id:'158',question:'This organization uses unannounced inspections to monitor standards:',options:['ISO','NCQA','CMS','HCAHPS'],correct_answer:2,domain:'Quality & Regulatory',difficulty:'hard',explanation:'The Centers for Medicare and Medicaid Services (CMS) uses unannounced inspections to monitor compliance.'},
  {id:'159',question:'Quality processes in decontamination include:',options:['Measuring chemicals','Checking instruments for cleanliness and functionality','Following all pick list instructions','All the above'],correct_answer:3,domain:'Decontamination',difficulty:'easy',explanation:'All three are quality processes in decontamination.'},
  {id:'160',question:'Assuming responsibility for survey readiness is one factor in:',options:['RCA','Keeping the focus on the patient','FMEA','Quality management'],correct_answer:3,domain:'Quality & Regulatory',difficulty:'medium',explanation:'Assuming responsibility for survey readiness is a factor in overall quality management.'},
  {id:'161',question:'Supply inspection should include:',options:['Only date-related items','Only in-house sterilized items','Checking for excessive handling','Checking the product\'s manufacturer date'],correct_answer:2,domain:'Sterile Storage',difficulty:'medium',explanation:'Supply inspection should include checking for excessive handling that could compromise sterility.'},
  {id:'162',question:'This organization issues regulations to help ensure medical devices are safe:',options:['FDA','EPA','DOT','OSHA'],correct_answer:0,domain:'Quality & Regulatory',difficulty:'easy',explanation:'The FDA issues regulations to help ensure medical devices are safe and effective.'},
  {id:'163',question:'Items that have been used for patient care should be considered:',options:['Contaminated','Disinfected','Ready to use','Decontaminated'],correct_answer:0,domain:'Decontamination',difficulty:'easy',explanation:'All items used for patient care must be considered contaminated and handled as such regardless of appearance.'},
  {id:'164',question:'Which of the following statements about IUSS is true?',options:['It is the sterilization method of choice for metal instruments','It is recommended as a primary sterilization process by AAMI and AORN','It reduces turnaround time because cleaning is not required','It should only be used when there is not enough time to process items using the wrapped method'],correct_answer:3,domain:'Sterilization',difficulty:'medium',explanation:'IUSS should only be used when there is insufficient time for wrapped sterilization.'},
  {id:'165',question:'Following liquid chemical sterilization items intended to be used as critical devices may be stored for:',options:['No storage — they should be used immediately','60 minutes','Four hours','One day'],correct_answer:0,domain:'Sterile Storage',difficulty:'hard',explanation:'Items processed by LCS have no sterile barrier and must be used immediately.'},
  {id:'166',question:'Which of the following can be used to close sterile packages?',options:['Sterilization indicator tape','Staples','Binder clips','Painter\'s tape'],correct_answer:0,domain:'Packaging',difficulty:'easy',explanation:'Sterilization indicator tape is the only acceptable closure for sterile packages.'},
  {id:'167',question:'An acceptable method of package closure that is also used as an external indicator is:',options:['Paper clips','Indicator tape','Staples','Binder clips'],correct_answer:1,domain:'Packaging',difficulty:'easy',explanation:'Sterilization indicator tape is both an acceptable closure method and an external chemical indicator.'},
  {id:'168',question:'Which must be inside every sterile package?',options:['Biological indicator','Chemical indicator','Count sheet','Expiration label'],correct_answer:1,domain:'Packaging',difficulty:'easy',explanation:'A chemical indicator must be inside every sterile package to confirm sterilant penetration.'},
  {id:'169',question:'The weakest part of a steam sterilizer is the:',options:['Jacket','Gasket','Door','Thermostatic valve'],correct_answer:1,domain:'Sterilization',difficulty:'medium',explanation:'The gasket is the weakest part — it is subject to wear and must be inspected regularly.'},
  {id:'170',question:'The most common reason for steam sterilization failure is:',options:['Lack of steam contact with the contents of the load','Insufficient temperature in the sterilizer chamber','Inadequate exposure time','Drying issues'],correct_answer:0,domain:'Sterilization',difficulty:'medium',explanation:'Lack of steam contact is the most common cause — caused by improper loading, air pockets, or inadequate packaging.'},
  {id:'171',question:'What is used daily to ensure air removal in pre-vacuum steam sterilizers?',options:['Infrared device','Bowie-Dick test','Humidity gauge','Sterilization parameter readout'],correct_answer:1,domain:'Sterilization',difficulty:'medium',explanation:'The Bowie-Dick test is run daily in pre-vacuum sterilizers to verify adequate air removal.'},
  {id:'172',question:'EO-sterilized items are aerated to remove residual:',options:['EO','Oxides','Peroxide','Alkali'],correct_answer:0,domain:'Sterilization',difficulty:'easy',explanation:'Aeration removes residual ethylene oxide gas from sterilized items — EO residue is toxic.'},
  {id:'173',question:'How should sterile packages be arranged to allow for stock rotation?',options:['Take from the bottom first','Last in first out','First in first out','Last in last out'],correct_answer:2,domain:'Sterile Storage',difficulty:'easy',explanation:'FIFO (First In First Out) is the correct stock rotation method.'},
  {id:'174',question:'The shelving system of choice for the sterile storage area is:',options:['Closed','Semi-closed','Open','Tracked'],correct_answer:0,domain:'Sterile Storage',difficulty:'easy',explanation:'Closed shelving is the preferred system for sterile storage.'},
  {id:'175',question:'The bottom shelf of any sterile storage system should be:',options:['Solid and eight to 10 inches from the floor','Solid and two to four inches from the floor','Made of wire and positioned two to four inches from the floor','Made of wire and positioned eight to 10 inches from the floor'],correct_answer:0,domain:'Sterile Storage',difficulty:'medium',explanation:'The bottom shelf must be solid and 8-10 inches from the floor.'},
  {id:'176',question:'Wrapped trays should not be stacked because:',options:['Tray contents may become damaged','It can cause holes in the wrappers','It will cause the shelving to bend','Trays will be more difficult to rotate'],correct_answer:1,domain:'Sterile Storage',difficulty:'medium',explanation:'Stacking wrapped trays causes holes in the wrappers compromising the sterile barrier.'},
  {id:'177',question:'Outside shipping containers should be removed before items enter sterile storage:',options:['True','False','Only for corrugated boxes','Only for items stored near in-house sterilized items'],correct_answer:0,domain:'Sterile Storage',difficulty:'easy',explanation:'Outside shipping containers must be removed — they are contaminated from transport.'},
  {id:'178',question:'Items should be stored at least how many inches below sprinkler heads?',options:['8','12','18','24'],correct_answer:2,domain:'Sterile Storage',difficulty:'hard',explanation:'Items must be stored at least 18 inches below sprinkler heads to allow full sprinkler operation.'},
  {id:'179',question:'The use of heat to kill all microorganisms except spores is called:',options:['Sterilization','Thermal disinfection','HLD','Mechanical disinfection'],correct_answer:1,domain:'Disinfection',difficulty:'medium',explanation:'Thermal disinfection uses heat to kill all microorganisms except spores.'},
  {id:'180',question:'These chemicals are used on animate living tissue to slow the growth of microorganisms:',options:['Glutaraldehydes','Disinfectants','Halogens','Antiseptics'],correct_answer:3,domain:'Disinfection',difficulty:'easy',explanation:'Antiseptics are used on living tissue to slow microbial growth — disinfectants are used on inanimate objects.'},
  {id:'181',question:'Items introduced directly into the bloodstream are classified as:',options:['Critical items','Semi-critical items','Non-critical items','Equipment'],correct_answer:0,domain:'Disinfection',difficulty:'easy',explanation:'Critical items contact sterile tissue or the bloodstream and require sterilization.'},
  {id:'182',question:'The process by which all forms of microorganisms are completely destroyed is:',options:['HLD','Thermal disinfection','Sterilization','Chemical disinfection'],correct_answer:2,domain:'Sterilization',difficulty:'easy',explanation:'Sterilization is the only process that destroys ALL forms of microorganisms including spores.'},
  {id:'183',question:'Which of the following are classified as high-level disinfectants?',options:['Glutaraldehydes and phenolics','Glutaraldehydes and OPA','Quats and phenolics','Halogens and OPA'],correct_answer:1,domain:'Disinfection',difficulty:'hard',explanation:'Glutaraldehydes and OPA are both classified as high-level disinfectants.'},
  {id:'184',question:'The place where the two parts of a ring-handled instrument meet and pivot is called the:',options:['Ratchet','Spring lock','Box lock','Jaw'],correct_answer:2,domain:'Instrumentation',difficulty:'easy',explanation:'The box lock is where the two parts of a ring-handled instrument meet and pivot.'},
  {id:'185',question:'Tissue forceps have:',options:['Serrated tips','Serrated locks','Gold tips','Teeth'],correct_answer:3,domain:'Instrumentation',difficulty:'easy',explanation:'Tissue forceps have teeth for gripping tissue — dressing forceps have serrations.'},
  {id:'186',question:'An osteotome is:',options:['Used to cut or shave bone','A retractor','Another name for a curette','Used to dissect soft tissue'],correct_answer:0,domain:'Instrumentation',difficulty:'easy',explanation:'An osteotome is a surgical instrument used to cut or shave bone.'},
  {id:'187',question:'Scissors with tungsten carbide cutting edges are usually identified by:',options:['Black handles','Silver handles','Gold handles','The letters TC'],correct_answer:2,domain:'Instrumentation',difficulty:'medium',explanation:'Tungsten carbide scissors are identified by gold handles or rings.'},
  {id:'188',question:'Which of the following steps happens first when processing flexible endoscopes?',options:['Leak testing','High-level disinfection/sterilization','Manual cleaning','Drying'],correct_answer:0,domain:'Endoscope Reprocessing',difficulty:'hard',explanation:'Leak testing must be performed FIRST before any cleaning — if the endoscope has a leak submersion causes internal damage.'},
  {id:'189',question:'Which statement about endoscopes is true?',options:['Flexible endoscopes are time-consuming to clean','Ultrasonic cleaning is the process of choice for endoscopes','Flexible endoscopes are not easily damaged','All endoscopes should be steam sterilized'],correct_answer:0,domain:'Endoscope Reprocessing',difficulty:'easy',explanation:'Flexible endoscopes ARE time-consuming to clean due to their complex channels and delicate construction.'},
  {id:'190',question:'The FDA classifies sterilization packaging as a:',options:['Class I medical device','Class II medical device','Class III medical device','Class IV medical device'],correct_answer:1,domain:'Packaging',difficulty:'medium',explanation:'The FDA classifies sterilization packaging as a Class II medical device.'},
  {id:'191',question:'IUSS documentation should include:',options:['Patient ID','Sterilizer number and cycle','Name of the instrument sterilized','All the above'],correct_answer:3,domain:'Sterilization',difficulty:'easy',explanation:'IUSS documentation must include patient ID, sterilizer number and cycle, and instrument name.'},
  {id:'192',question:'How frequently should a sterilizer\'s chamber drain strainer be removed and cleaned?',options:['Daily','After each use','Once weekly','Only when indicated by the control gauge'],correct_answer:0,domain:'Sterilization',difficulty:'easy',explanation:'The drain strainer should be removed and cleaned daily to prevent buildup.'},
  {id:'193',question:'Humidity in the sterile storage area should be:',options:['Less than 30%','30% to 60%','Greater than 60%','No specific requirement'],correct_answer:1,domain:'Sterile Storage',difficulty:'hard',explanation:'Humidity in sterile storage must be maintained at 30-60%.'},
  {id:'194',question:'Which of the following is not a goal of point-of-use treatment?',options:['Removing gross soil','Transporting instruments within two hours of the end of a procedure','Preventing cross-contamination','Preventing damage during transport'],correct_answer:1,domain:'Infection Prevention',difficulty:'medium',explanation:'Transporting instruments within two hours is NOT a goal of point-of-use treatment.'},
  {id:'195',question:'Which of the following can cause a wet pack?',options:['Placing dry instruments within a package','Heavy or dense instrument sets','Standing a basin on edge and tilting for drainage','Ensuring there is visible space between packs'],correct_answer:1,domain:'Sterilization',difficulty:'hard',explanation:'Heavy or dense instrument sets retain moisture during the drying cycle.'},
  {id:'196',question:'The three main phases of a terminal steam sterilizer cycle are:',options:['Gravity exposure and exhaust','Pre-vacuum exposure and exhaust','Exposure exhaust and dry','Conditioning exposure and exhaust'],correct_answer:3,domain:'Sterilization',difficulty:'hard',explanation:'The three phases are conditioning (air removal), exposure (sterilization), and exhaust (pressure release and drying).'},
  {id:'197',question:'Which sterilization method can permeate throughout a wide range of materials to reach recessed areas?',options:['Hydrogen peroxide','Steam sterilization','Ethylene oxide','Glutaraldehyde'],correct_answer:2,domain:'Sterilization',difficulty:'hard',explanation:'Ethylene oxide gas permeates through a wide range of materials and packaging to reach recessed areas.'},
  {id:'198',question:'Sterile storage areas should have:',options:['Positive airflow and at least 10 air exchanges per hour','Positive airflow and at least four air exchanges per hour','Negative airflow and at least 10 air exchanges per hour','Negative airflow and at least four air exchanges per hour'],correct_answer:0,domain:'Sterile Storage',difficulty:'hard',explanation:'Sterile storage must have positive airflow and at least 10 air exchanges per hour.'},
  {id:'199',question:'Written cleaning instructions for surgical instruments should be provided by the:',options:['Mechanical washer manufacturer','Device manufacturer','Detergent manufacturer','Healthcare facility'],correct_answer:1,domain:'Decontamination',difficulty:'easy',explanation:'The device manufacturer provides written cleaning instructions (IFU) — these must be followed to ensure proper cleaning.'},
  {id:'200',question:'What is the preferred pH for detergents used for most cleaning processes?',options:['Low pH','High pH','Neutral pH','It depends on water temperature and exposure time'],correct_answer:2,domain:'Decontamination',difficulty:'medium',explanation:'Neutral pH detergents are preferred for most instrument cleaning — effective without damaging instrument surfaces.'},
  {id:'201',question:'Instruments should be kept together with their sets in the user area because:',options:['It reduces the risk that multi-part components will be misplaced','The chance that instruments will be lost is decreased','Reassembly of the set will not be delayed','All the above'],correct_answer:3,domain:'Decontamination',difficulty:'easy',explanation:'All three are valid reasons — keeping sets together prevents lost components, reduces loss risk, and prevents assembly delays.'},
  {id:'202',question:'If soiled items are held in user units before being picked up they must be kept:',options:['At the patient\'s bedside until SP collects them','In a locked area on the nursing unit','In a designated holding area','In a container of water'],correct_answer:2,domain:'Decontamination',difficulty:'medium',explanation:'Soiled items must be kept in a designated holding area — not at bedside or in water which promotes bacterial growth.'},
  {id:'203',question:'Which is NOT a reason for point-of-use treatment?',options:['It helps reduce the likelihood of biofilm formation','It reduces the SP workload','Dried soil requires more aggressive cleaning measures','It helps prolong the life of the instruments'],correct_answer:1,domain:'Decontamination',difficulty:'hard',explanation:'Point-of-use treatment does not reduce the SP workload — it adds a step at the user end.'},
  {id:'204',question:'A goal of soiled transport is to:',options:['Minimize the risk of cross-contamination','Decrease the time it takes to get soiled items to decontamination','Decrease microbial growth','All the above'],correct_answer:3,domain:'Decontamination',difficulty:'easy',explanation:'All three are goals of soiled transport — minimizing contamination risk, speed, and microbial growth control.'},
  {id:'205',question:'Before transporting soiled devices SP technicians should be aware of:',options:['The number of case carts in the decontamination area','Visiting hours so carts are not transported when visitors are in hallways','The ergonomic principles of lifting pushing and pulling','All the above'],correct_answer:3,domain:'Decontamination',difficulty:'easy',explanation:'All three are important considerations before transporting soiled devices.'},
  {id:'206',question:'Off-site transport policies and procedures should define:',options:['Soil levels','Color of biohazard signage','How to remove biofilm','Separation of clean and dirty'],correct_answer:3,domain:'Decontamination',difficulty:'medium',explanation:'Off-site transport policies must define separation of clean and dirty items to prevent cross-contamination.'},
  {id:'207',question:'Which is not a goal of point-of-use treatment?',options:['Removal of gross soil','Preventing cross-contamination','Transporting items within two hours of the end of the procedure','Preventing damage during transport'],correct_answer:2,domain:'Decontamination',difficulty:'medium',explanation:'Transporting within two hours is NOT a goal of point-of-use treatment.'},
  {id:'208',question:'The best way to transport contaminated instruments is in a/an:',options:['Open case cart','Dedicated soiled elevator','Cart in a patient elevator','Cart in a high-traffic area'],correct_answer:1,domain:'Decontamination',difficulty:'easy',explanation:'A dedicated soiled elevator minimizes exposure to patients, visitors, and clean areas during transport.'},
  {id:'209',question:'During point-of-use treatment instruments should NOT:',options:['Have open hinges','Be disassembled','Be placed in a basin with saline to keep them moist','Be arranged in an orderly manner'],correct_answer:1,domain:'Decontamination',difficulty:'hard',explanation:'Instruments should NOT be disassembled at point-of-use — disassembly is done in the decontamination area.'},
  {id:'210',question:'Injuries or disorders of the muscles nerves tendons or joints are called:',options:['Pain points','Musculoskeletal disorders','Workplace disorders','Ergonomic injuries'],correct_answer:1,domain:'Safety',difficulty:'easy',explanation:'Musculoskeletal disorders are injuries or disorders affecting muscles, nerves, tendons, or joints.'},
  {id:'211',question:'The major source of soiled items received by the SPD is:',options:['Pharmacy','Surgery','Supply Chain','Infection Prevention'],correct_answer:1,domain:'Decontamination',difficulty:'easy',explanation:'Surgery (the Operating Room) is the major source of soiled instruments received by the SPD.'},
  {id:'212',question:'When instruments are prepared for transport to the decontamination area it is important to keep them:',options:['Dry and assembled','Moist','Disassembled','In sterile water'],correct_answer:1,domain:'Decontamination',difficulty:'easy',explanation:'Instruments must be kept moist during transport to prevent soil from drying and hardening on surfaces.'},
  {id:'213',question:'Tissue body fat blood and other bodily substances are examples of:',options:['Biofilm','Biohazard','Gross soil','Contamination'],correct_answer:2,domain:'Decontamination',difficulty:'easy',explanation:'Gross soil refers to visible tissue, body fat, blood and other bodily substances on instruments.'},
  {id:'214',question:'Soiled instruments should be transported in a/an:',options:['Open case cart','Closed hard-sided cart','Wire basket','Biohazard bag'],correct_answer:1,domain:'Decontamination',difficulty:'easy',explanation:'Soiled instruments must be transported in a closed hard-sided cart to contain contamination and protect staff.'},
  {id:'215',question:'Containers and carts used to transport contaminated items should not be used to transport clean items unless they have been thoroughly:',options:['Rinsed','Sterilized','Decontaminated','Inspected'],correct_answer:2,domain:'Decontamination',difficulty:'easy',explanation:'Transport containers must be thoroughly decontaminated between uses to prevent cross-contamination of clean items.'},
  {id:'216',question:'What is the preferred pH for detergents used for most cleaning processes?',options:['Low pH','High pH','Neutral pH','It depends on water temperature and exposure time'],correct_answer:2,domain:'Decontamination',difficulty:'medium',explanation:'Neutral pH detergents are preferred for most instrument cleaning — effective without damaging instrument surfaces.'},
  {id:'217',question:'Which statement about use of washer-disinfectors is NOT true?',options:['Multi-level trays should be separated','Trays with lids should be opened','Instruments should be disassembled and opened','All items should be washed on the same cycle'],correct_answer:3,domain:'Decontamination',difficulty:'medium',explanation:'All items should NOT be washed on the same cycle — different instruments have different cleaning requirements.'},
  {id:'218',question:'Water must be degassed each time an ultrasonic cleaner\'s tank is changed because excess bubbles:',options:['Reduce the energy of the cavitation process','Reduce the effectiveness of the detergent','Decrease the temperature of the tank','Make it difficult to see items being cleaned'],correct_answer:0,domain:'Decontamination',difficulty:'hard',explanation:'Excess air bubbles reduce the energy of the cavitation process — degassing removes these bubbles to maximize cleaning.'},
  {id:'219',question:'Written cleaning instructions for surgical instruments should be provided by the:',options:['Mechanical washer manufacturer','Device manufacturer','Detergent manufacturer','Healthcare facility'],correct_answer:1,domain:'Decontamination',difficulty:'easy',explanation:'The device manufacturer provides written cleaning instructions (IFU) — these must be followed to ensure proper cleaning.'},
  {id:'220',question:'Floors and walls in the decontamination area should be:',options:['Cleaned monthly','Constructed to tolerate cleaning chemicals','Constructed of particulate materials','All the above'],correct_answer:1,domain:'Decontamination',difficulty:'easy',explanation:'Floors and walls in decontamination must be constructed to tolerate the cleaning chemicals used in that environment.'},
  {id:'221',question:'Untreated water:',options:['Increases the likelihood of mineral scale deposits','Decreases the likelihood of mineral scale deposits','Is recommended for use during the detergent cycle','Is used for the final rinse process'],correct_answer:0,domain:'Decontamination',difficulty:'medium',explanation:'Untreated water contains minerals that leave deposits on instruments — treated water prevents scale buildup.'},
  {id:'222',question:'These are used to breakdown fatty deposits on instruments:',options:['Protease enzymes','Lipase enzymes','Amylase enzymes','Neutral-pH cleaners'],correct_answer:1,domain:'Decontamination',difficulty:'hard',explanation:'Lipase enzymes break down fatty deposits — protease breaks down proteins, amylase breaks down starches.'},
  {id:'223',question:'Instrument lubrication is performed:',options:['Immediately before use','After sterilization','After cleaning and before packaging','Before cleaning'],correct_answer:2,domain:'Assembly',difficulty:'easy',explanation:'Lubrication is performed after cleaning and before packaging — it protects instruments and does not interfere with sterilization.'},
  {id:'224',question:'To prevent coagulation of proteins instruments should be pre-rinsed using:',options:['Cool water','Hot water','A neutral detergent','A disinfectant rinse'],correct_answer:0,domain:'Decontamination',difficulty:'medium',explanation:'Cool water prevents protein coagulation — hot water causes proteins to cook onto instrument surfaces.'},
  {id:'225',question:'During manual cleaning instruments should be brushed using a:',options:['Circular motion','To-and-fro motion','Stiff metal brush','Scrubbing pad'],correct_answer:1,domain:'Decontamination',difficulty:'medium',explanation:'To-and-fro motion is recommended for manual cleaning — circular motion can push debris into crevices.'},
  {id:'226',question:'Powered surgical instruments cannot be immersed in water:',options:['True','False','Only battery-powered instruments','Only pneumatic instruments'],correct_answer:0,domain:'Decontamination',difficulty:'easy',explanation:'Powered surgical instruments cannot be immersed — they must be cleaned according to manufacturer IFU.'},
  {id:'227',question:'Ultrasonic irrigators are used to:',options:['Clean prion items','Perform finite cleaning for powered surgical equipment','Clean devices with lumens','Clean flexible endoscopes with lumens'],correct_answer:2,domain:'Decontamination',difficulty:'hard',explanation:'Ultrasonic irrigators flush lumens and channels with cleaning solution to remove debris from internal surfaces.'},
  {id:'228',question:'Rigid container filter retention plates should be:',options:['Removed from the container and lid and cleaned separately','Manually cleaned and attached to the lid for mechanical cleaning','Left attached to the lid during the cleaning process','None of the above'],correct_answer:0,domain:'Decontamination',difficulty:'medium',explanation:'Filter retention plates must be removed from both the container and lid and cleaned separately.'},
  {id:'229',question:'Instruments with lumens should always be soaked in a:',options:['Vertical position','Horizontal position','Disassembled position','Standing position'],correct_answer:0,domain:'Decontamination',difficulty:'medium',explanation:'Instruments with lumens must be soaked vertically so fluid can enter and drain from the lumen by gravity.'},
  {id:'230',question:'The mechanical process by which an ultrasonic cleaner works is called:',options:['Impingement','Cavitation','Aerosolization','Emulsification'],correct_answer:1,domain:'Decontamination',difficulty:'easy',explanation:'Cavitation is the process by which ultrasonic cleaners work — high-frequency sound waves create tiny bubbles that implode removing soil.'},
  {id:'231',question:'This low-level disinfectant is incompatible with soap:',options:['Alcohol','Phenol','Quaternary ammonium compounds','OPA'],correct_answer:2,domain:'Disinfection',difficulty:'hard',explanation:'Quaternary ammonium compounds are inactivated by soap and organic materials — they must never be mixed with soap.'},
  {id:'232',question:'When working with glutaraldehyde technicians should always wear:',options:['Latex gloves','Nitrile gloves','Decontamination gloves','Exam gloves'],correct_answer:1,domain:'Safety',difficulty:'medium',explanation:'Nitrile gloves must be worn when working with glutaraldehyde — latex gloves do not provide adequate protection.'},
  {id:'233',question:'How are items that have undergone HLD dried?',options:['Air dried','With HEPA-filtered air','If using an AER no extra drying is required if an alcohol flush is included','All the above'],correct_answer:3,domain:'Disinfection',difficulty:'medium',explanation:'All three are acceptable drying methods for HLD items depending on the process and equipment used.'},
  {id:'234',question:'In a washer-disinfector the key source of disinfection is:',options:['Hydrogen peroxide','Water temperature','Heat','Disinfecting detergent'],correct_answer:2,domain:'Decontamination',difficulty:'medium',explanation:'Heat is the primary source of disinfection in a washer-disinfector.'},
  {id:'235',question:'The use of test strips to test the MEC in HLD solutions is required:',options:['Weekly preferably daily','Daily','Each time the solution will be used','Only when manual soaking systems are used'],correct_answer:2,domain:'Disinfection',difficulty:'hard',explanation:'MEC test strips must be used each time the HLD solution will be used to ensure adequate concentration.'},
  {id:'236',question:'The use of heat to kill all microorganisms except spores is called:',options:['Sterilization','Thermal disinfection','HLD','Mechanical disinfection'],correct_answer:1,domain:'Disinfection',difficulty:'medium',explanation:'Thermal disinfection uses heat to kill all microorganisms except spores.'},
  {id:'237',question:'These chemicals are used on animate living tissue to slow the growth of microorganisms:',options:['Glutaraldehydes','Disinfectants','Halogens','Antiseptics'],correct_answer:3,domain:'Disinfection',difficulty:'easy',explanation:'Antiseptics are used on living tissue to slow microbial growth — disinfectants are used on inanimate objects.'},
  {id:'238',question:'Items introduced directly into the bloodstream are classified as:',options:['Critical items','Semi-critical items','Non-critical items','Equipment'],correct_answer:0,domain:'Disinfection',difficulty:'easy',explanation:'Critical items contact sterile tissue or the bloodstream and require sterilization per the Spaulding Classification System.'},
  {id:'239',question:'The process by which all forms of microorganisms are completely destroyed is:',options:['HLD','Thermal disinfection','Sterilization','Chemical disinfection'],correct_answer:2,domain:'Sterilization',difficulty:'easy',explanation:'Sterilization is the only process that destroys ALL forms of microorganisms including spores.'},
  {id:'240',question:'Iodophors are a member of this chemical family:',options:['Halogens','Quats','Alcohol','Phenolics'],correct_answer:0,domain:'Disinfection',difficulty:'medium',explanation:'Iodophors are iodine-based compounds belonging to the halogen family of disinfectants.'},
  {id:'241',question:'Phenolics are classified as:',options:['Low- to intermediate-level disinfectants','Intermediate- to high-level disinfectants','High-level disinfectants','Sterilants'],correct_answer:0,domain:'Disinfection',difficulty:'medium',explanation:'Phenolics are low- to intermediate-level disinfectants.'},
  {id:'242',question:'Which of the following are classified as high-level disinfectants?',options:['Glutaraldehydes and phenolics','Glutaraldehydes and OPA','Quats and phenolics','Halogens and OPA'],correct_answer:1,domain:'Disinfection',difficulty:'hard',explanation:'Glutaraldehydes and OPA are both classified as high-level disinfectants.'},
  {id:'243',question:'Thermal disinfection is accomplished using:',options:['Heated chemicals','Heated glutaraldehyde','Prolonged high-pressure steam','Heat'],correct_answer:3,domain:'Disinfection',difficulty:'easy',explanation:'Thermal disinfection uses heat alone.'},
  {id:'244',question:'How long must alcohol remain in wet contact with an item to achieve reasonable disinfection?',options:['One to two minutes','Two to three minutes','Five to 10 minutes','10 to 20 minutes'],correct_answer:2,domain:'Disinfection',difficulty:'hard',explanation:'Alcohol must remain in wet contact for five to 10 minutes to achieve effective disinfection.'},
  {id:'245',question:'Which chemical is the best choice for HLD of instruments?',options:['Phenolics','Chlorine','Iodophors','OPA'],correct_answer:3,domain:'Disinfection',difficulty:'hard',explanation:'OPA is the best choice for HLD of instruments — effective, less irritating than glutaraldehyde.'},
  {id:'246',question:'A chemical that kills most pathogenic organisms but does not kill spores is called a:',options:['Sterilant','Antiseptic','Disinfectant','Bactericidal agent'],correct_answer:2,domain:'Disinfection',difficulty:'medium',explanation:'A disinfectant kills most pathogenic organisms but not spores — sterilants destroy all forms of microbial life.'},
  {id:'247',question:'The length of time an item must remain in wet contact with a disinfectant is called:',options:['Activation time','Wet contact time','Disinfectant holding time','Sterilization time'],correct_answer:2,domain:'Disinfection',difficulty:'easy',explanation:'Disinfectant holding time is the required contact time for the disinfectant to be effective.'},
  {id:'248',question:'MEC testing using test strips is required:',options:['Weekly','Daily','Each time the solution is used','Only when the solution appears cloudy'],correct_answer:2,domain:'Disinfection',difficulty:'hard',explanation:'MEC test strips must be used each time the HLD solution is used to verify adequate concentration.'},
  {id:'249',question:'When manually disinfecting lumens care should be taken to ensure there are no:',options:['Detergent residues','Air bubbles','Mineral deposits','Chemical residues'],correct_answer:1,domain:'Disinfection',difficulty:'medium',explanation:'Air bubbles inside lumens prevent the disinfectant from contacting all surfaces.'},
  {id:'250',question:'Microgrind and supercut scissors are usually identified by:',options:['Gold rings','Black rings','Teeth on one blade serrations on the other','One black ring and one gold ring'],correct_answer:1,domain:'Instrumentation',difficulty:'medium',explanation:'Microgrind and supercut scissors have black rings on the handles to identify them as premium cutting instruments.'},
  {id:'251',question:'This type of needle holder insert is harder and lasts longer:',options:['Stainless steel','Chromium oxide','Nickel','Tungsten carbide'],correct_answer:3,domain:'Instrumentation',difficulty:'medium',explanation:'Tungsten carbide inserts are harder and last longer than stainless steel.'},
  {id:'252',question:'The place where the two parts of a ring-handled instrument meet and pivot is called the:',options:['Ratchet','Spring lock','Box lock','Jaw'],correct_answer:2,domain:'Instrumentation',difficulty:'easy',explanation:'The box lock is where the two parts of a ring-handled instrument meet and pivot.'},
  {id:'253',question:'The process used to give instruments a mirror finish is called:',options:['Heat treating','Wiping with chromium oxide','Forging with more nickel','Polishing'],correct_answer:3,domain:'Instrumentation',difficulty:'medium',explanation:'Polishing gives instruments a mirror finish.'},
  {id:'254',question:'Tissue forceps have:',options:['Serrated tips','Serrated locks','Gold tips','Teeth'],correct_answer:3,domain:'Instrumentation',difficulty:'easy',explanation:'Tissue forceps have teeth for gripping tissue — dressing forceps have serrations.'},
  {id:'255',question:'During instrument manufacturing the process used to build a protective layer on instruments is called:',options:['Passivation','Forging','Polishing','Milling'],correct_answer:0,domain:'Instrumentation',difficulty:'medium',explanation:'Passivation builds a protective chromium oxide layer on stainless steel instruments.'},
  {id:'256',question:'The part of a hemostat that locks and holds it in position is called the:',options:['Ratchet','Box lock','Spring lock','Jaw'],correct_answer:0,domain:'Instrumentation',difficulty:'easy',explanation:'The ratchet is the locking mechanism on hemostats and other clamps.'},
  {id:'257',question:'An acceptable method for instrument identification is:',options:['Powder coating','Identification tape','Laser etching','All the above'],correct_answer:2,domain:'Instrumentation',difficulty:'medium',explanation:'Laser etching is an acceptable identification method — identification tape can interfere with sterilization.'},
  {id:'258',question:'Which solution can damage surgical instrumentation?',options:['Betadine','Sterile water','Critical water','Utility water'],correct_answer:0,domain:'Instrumentation',difficulty:'medium',explanation:'Betadine is corrosive to surgical instruments and can cause pitting and staining.'},
  {id:'259',question:'An osteotome is:',options:['Used to cut or shave bone','A retractor','Another name for a curette','Used to dissect soft tissue'],correct_answer:0,domain:'Instrumentation',difficulty:'easy',explanation:'An osteotome is a surgical instrument used to cut or shave bone.'},
  {id:'260',question:'The purpose of a suction stylet is to:',options:['Unclog the suction during surgery','Clean the suction in the decontamination area','Facilitate the sterilization process','Provide a measuring guide for the surgeon'],correct_answer:0,domain:'Instrumentation',difficulty:'medium',explanation:'A suction stylet is used to unclog the suction cannula during surgery when it becomes blocked with tissue.'},
  {id:'261',question:'Kerrison and laminectomy rongeurs should be tested using:',options:['Tissue paper','A plastic dowel rod','Rubber testing material','An index card'],correct_answer:1,domain:'Instrumentation',difficulty:'hard',explanation:'A plastic dowel rod is used to test Kerrison and laminectomy rongeurs.'},
  {id:'262',question:'Scissors with tungsten carbide cutting edges are usually identified by:',options:['Black handles','Silver handles','Gold handles','The letters TC'],correct_answer:2,domain:'Instrumentation',difficulty:'medium',explanation:'Tungsten carbide scissors are identified by gold handles or rings.'},
  {id:'263',question:'The best way to clean a suction lumen is:',options:['Using warm running water','Using the proper-sized brush','Soaking in an enzymatic solution for three minutes','Using the appropriate stylet'],correct_answer:1,domain:'Decontamination',difficulty:'medium',explanation:'Using the proper-sized brush is the best way to clean a suction lumen.'},
  {id:'264',question:'To properly test the sharpness of scissors measuring 4.5 inches and shorter use:',options:['Yellow test material','Red test material','An index card','Orange test material'],correct_answer:1,domain:'Instrumentation',difficulty:'hard',explanation:'Red test material is used to test scissors 4.5 inches and shorter.'},
  {id:'265',question:'A self-retaining retractor is called a:',options:['Gelpi','Richardson','Kerrison','Hemostat'],correct_answer:0,domain:'Instrumentation',difficulty:'medium',explanation:'The Gelpi retractor is self-retaining — it holds itself in place without an assistant.'},
  {id:'266',question:'Tissue forceps have teeth and dressing forceps have:',options:['Teeth','Serrations','Gold tips','Smooth tips'],correct_answer:1,domain:'Instrumentation',difficulty:'easy',explanation:'Tissue forceps have teeth for gripping tissue — dressing forceps have serrations.'},
  {id:'267',question:'Tungsten carbide scissor blades hold a sharp edge longer than stainless steel blades:',options:['True','False','Only for small scissors','Only for large scissors'],correct_answer:0,domain:'Instrumentation',difficulty:'easy',explanation:'True — tungsten carbide is harder than stainless steel and holds a sharp edge significantly longer.'},
  {id:'268',question:'Laser etching is an acceptable method for marking instruments:',options:['True','False','Only for stainless steel','Only for titanium'],correct_answer:0,domain:'Instrumentation',difficulty:'easy',explanation:'True — laser etching is an acceptable permanent identification method that does not damage instruments.'},
  {id:'269',question:'The first step to inspect the insulation of a laparoscopic instrument is to:',options:['Check the collar at the distal tip','Try to slide the insulation back','Check the handle for chipping or cracking','Visually check the instrument\'s shaft'],correct_answer:3,domain:'Instrumentation',difficulty:'medium',explanation:'Visually checking the instrument\'s shaft is the first step — look for cuts, abrasions, or missing insulation.'},
  {id:'270',question:'Which of the following steps happens first when processing flexible endoscopes?',options:['Leak testing','High-level disinfection/sterilization','Manual cleaning','Drying'],correct_answer:0,domain:'Endoscope Reprocessing',difficulty:'hard',explanation:'Leak testing must be performed FIRST before any cleaning — if the endoscope has a leak submersion causes internal damage.'},
  {id:'271',question:'Pneumatic cords are a cleaning concern because:',options:['Of their length','They are dark in color so soil is difficult to see','The electrical plug is very delicate','The cord does not detach from the device'],correct_answer:1,domain:'Decontamination',difficulty:'medium',explanation:'Pneumatic cords are dark in color making soil very difficult to see.'},
  {id:'272',question:'The purpose of using a decontamination battery or hose when cleaning powered surgical instruments is to:',options:['Keep fluid from entering the unit','Keep batteries and cords clean','Prevent electrical shock','Test the unit while cleaning'],correct_answer:0,domain:'Decontamination',difficulty:'medium',explanation:'The decontamination battery or hose keeps fluid from entering the instrument unit during cleaning.'},
  {id:'273',question:'One of the main reasons for powered surgical instrument repair is:',options:['Poor sterilization practices','Lack of preventative maintenance','Kinking of the umbilical cable','Improper storage'],correct_answer:1,domain:'Equipment',difficulty:'medium',explanation:'Lack of preventative maintenance is the primary reason for powered surgical instrument repair.'},
  {id:'274',question:'Powered surgical instrument attachments can be peel packaged for sterilization if approved by the manufacturer:',options:['True','False','Only for electric instruments','Only for pneumatic instruments'],correct_answer:0,domain:'Sterilization',difficulty:'hard',explanation:'Attachments can be peel packaged for sterilization if approved by the manufacturer.'},
  {id:'275',question:'Loaned instruments should:',options:['Be decontaminated if they appear soiled upon arrival','Be sterilized using a low-temperature process','Be decontaminated before use','Should not be used'],correct_answer:2,domain:'Decontamination',difficulty:'medium',explanation:'All loaned instruments must be decontaminated before use regardless of appearance.'},
  {id:'276',question:'Information regarding cleaning processes for endoscopes should be provided by the:',options:['SGNA','APIC','Instrument manufacturer','OR staff'],correct_answer:2,domain:'Endoscope Reprocessing',difficulty:'medium',explanation:'The instrument manufacturer provides cleaning instructions (IFU) that must be followed.'},
  {id:'277',question:'Which statement about endoscopes is true?',options:['Flexible endoscopes are time-consuming to clean','Ultrasonic cleaning is the process of choice for endoscopes','Flexible endoscopes are not easily damaged','All endoscopes should be steam sterilized'],correct_answer:0,domain:'Endoscope Reprocessing',difficulty:'easy',explanation:'Flexible endoscopes ARE time-consuming to clean due to their complex channels and delicate construction.'},
  {id:'278',question:'Electronic testing of laparoscopic insulation should be done:',options:['In the decontamination area prior to cleaning','In the clean assembly area prior to set assembly','At the factory or onsite repair unit','In the OR at the end of the procedure'],correct_answer:1,domain:'Instrumentation',difficulty:'hard',explanation:'Electronic insulation testing is done in the clean assembly area prior to set assembly.'},
  {id:'279',question:'Pneumatic hoses should be pressurized for proper inspection:',options:['True','False','Only flexible hoses','Only pneumatic cords'],correct_answer:0,domain:'Equipment',difficulty:'hard',explanation:'Pneumatic hoses should be pressurized for proper inspection — this tests for leaks.'},
  {id:'280',question:'Powered surgical instrument batteries should be charged per the manufacturers IFU:',options:['In the OR','In the decontamination area','Before sterilization','During PM inspections'],correct_answer:2,domain:'Equipment',difficulty:'medium',explanation:'Batteries should be charged per manufacturer IFU — typically before sterilization.'},
  {id:'281',question:'Semi-rigid endoscopes should be leak tested prior to cleaning:',options:['True','False','Only when visibly damaged','Only for urological procedures'],correct_answer:0,domain:'Endoscope Reprocessing',difficulty:'medium',explanation:'Semi-rigid endoscopes should be leak tested prior to cleaning to detect leaks before submersion.'},
  {id:'282',question:'Endoscopic cameras should be inspected for:',options:['Cuts nicks or other damage to the cable','Lens clarity only','Battery charge','Sterilization date'],correct_answer:0,domain:'Instrumentation',difficulty:'medium',explanation:'Endoscopic camera cables should be inspected for cuts, nicks, or other damage — cable damage is a common cause of failure.'},
  {id:'283',question:'Robotic instruments:',options:['May have exposed cables','Are processed the same as laparoscopic instruments','Require extensive PM','Are heavy and less susceptible to damage'],correct_answer:2,domain:'Equipment',difficulty:'hard',explanation:'Robotic instruments require extensive preventative maintenance due to their complex mechanical and electrical components.'},
  {id:'284',question:'Leak testing should be performed on each flexible endoscope:',options:['Before every use','On an annual basis only','After every cleaning cycle','Before every cleaning'],correct_answer:3,domain:'Endoscope Reprocessing',difficulty:'hard',explanation:'Leak testing must be performed before every cleaning — submersing a leaking endoscope causes irreparable internal damage.'},
  {id:'285',question:'Loaned instrument trays received sterile from other facilities must be decontaminated and re-sterilized before use:',options:['True','False','Only if visibly soiled','Only if more than 30 days old'],correct_answer:0,domain:'Decontamination',difficulty:'hard',explanation:'All loaned instruments must be decontaminated and re-sterilized regardless of how they arrive.'},
  {id:'286',question:'Endoscope channels should be stored:',options:['Moist','Completely dry','Filled with sterile water','With alcohol in the channels'],correct_answer:1,domain:'Endoscope Reprocessing',difficulty:'medium',explanation:'Endoscope channels must be completely dry before storage — moisture promotes microbial growth.'},
  {id:'287',question:'The FDA classifies sterilization packaging as a:',options:['Class I medical device','Class II medical device','Class III medical device','Class IV medical device'],correct_answer:1,domain:'Packaging',difficulty:'medium',explanation:'The FDA classifies sterilization packaging as a Class II medical device.'},
  {id:'288',question:'Which of the following is NOT an acceptable sterilization packaging material?',options:['Muslin','Barrier cloth','Canvas','Twill'],correct_answer:2,domain:'Packaging',difficulty:'hard',explanation:'Canvas is not an acceptable sterilization packaging material.'},
  {id:'289',question:'Count sheets provide:',options:['A description of each instrument in detail','Information for OR trays only','A detailed list of tray contents','Information from the manufacturer\'s IFU'],correct_answer:2,domain:'Assembly',difficulty:'easy',explanation:'Count sheets provide a detailed list of tray contents — they are used to verify all instruments are accounted for.'},
  {id:'290',question:'When arranging paper/plastic pouches in a sterilizer the pouches should be arranged:',options:['Paper to plastic','Paper to paper','Plastic to plastic','Flat'],correct_answer:0,domain:'Packaging',difficulty:'medium',explanation:'Paper/plastic pouches must be arranged paper to plastic so steam can penetrate through the paper side.'},
  {id:'291',question:'How often should the insulation of electrosurgical instruments be tested for integrity?',options:['Only when requested','Every time the instrument is processed','Every fifth time the instrument is processed','Weekly'],correct_answer:1,domain:'Instrumentation',difficulty:'hard',explanation:'Electrosurgical instrument insulation must be tested every time it is processed.'},
  {id:'292',question:'Spunbonded polyolefin is intended for use in this sterilization process:',options:['Steam','Hydrogen peroxide','Liquid','Gravity'],correct_answer:1,domain:'Packaging',difficulty:'hard',explanation:'Spunbonded polyolefin (Tyvek) is designed for hydrogen peroxide sterilization.'},
  {id:'293',question:'When placing hinged instruments in an instrument tray:',options:['Lock the handles to prevent damage','Arrange all sharps on top','Arrange in order of use','Unlock the handles and open the instruments'],correct_answer:3,domain:'Assembly',difficulty:'easy',explanation:'Hinged instruments must be unlocked and open so steam can reach all joint surfaces during sterilization.'},
  {id:'294',question:'Instruments are placed into sets:',options:['Wet','Soiled','Dry','Assembled'],correct_answer:2,domain:'Assembly',difficulty:'easy',explanation:'Instruments must be completely dry before being placed into sets — moisture causes wet packs.'},
  {id:'295',question:'Which cannot be used in an instrument set to protect delicate instruments?',options:['Tip protectors','Plastic peel packs','Approved foam pouches','Silicon mats'],correct_answer:1,domain:'Packaging',difficulty:'hard',explanation:'Plastic peel packs cannot be used inside sets to protect instruments — they trap moisture and prevent steam penetration.'},
  {id:'296',question:'This type of CI is a cycle-specific verification indicator designed to react to all critical parameters:',options:['Type 3','Type 4','Type 5','Type 6'],correct_answer:2,domain:'Sterilization',difficulty:'hard',explanation:'Type 5 integrating indicators react to all critical sterilization parameters — the most comprehensive CI type.'},
  {id:'297',question:'Which packaging system is required to be packaged twice for double sterile presentation?',options:['Sterilization container','Sequential flat wrapper','Simultaneous flat wrapper','Containment device'],correct_answer:1,domain:'Packaging',difficulty:'medium',explanation:'Sequential flat wrapping applies two wraps in sequence creating a package within a package.'},
  {id:'298',question:'Which of the following items can cause superheating within a sterilization cycle?',options:['Soiled instruments','Wet instruments','Instruments with insulation','Pre-packaged sterile towels'],correct_answer:2,domain:'Sterilization',difficulty:'hard',explanation:'Instruments with insulation can cause superheating — the insulation traps heat.'},
  {id:'299',question:'Plastic containers take longer to dry because they:',options:['Lack metal which produces heat by conduction','Are lighter','Crack easily leaving areas for moisture to hide','Can hold more instruments'],correct_answer:0,domain:'Sterilization',difficulty:'hard',explanation:'Plastic lacks metal\'s thermal conductivity — metal conducts heat that aids in drying.'},
  {id:'300',question:'Which of the following can be used to close sterile packages?',options:['Sterilization indicator tape','Staples','Binder clips','Painter\'s tape'],correct_answer:0,domain:'Packaging',difficulty:'easy',explanation:'Sterilization indicator tape is the only acceptable closure for sterile packages.'},
  {id:'301',question:'An acceptable method of package closure that is also used as an external indicator is:',options:['Paper clips','Indicator tape','Staples','Binder clips'],correct_answer:1,domain:'Packaging',difficulty:'easy',explanation:'Sterilization indicator tape is both an acceptable closure method and an external chemical indicator.'},
  {id:'302',question:'Which must be inside every sterile package?',options:['Biological indicator','Chemical indicator','Count sheet','Expiration label'],correct_answer:1,domain:'Packaging',difficulty:'easy',explanation:'A chemical indicator must be inside every sterile package to confirm sterilant penetration.'},
  {id:'303',question:'The flat-wrapping technique that applies one wrap on top of another is called:',options:['Square fold','Sequential','Simultaneous','Envelope fold'],correct_answer:1,domain:'Packaging',difficulty:'medium',explanation:'Sequential wrapping applies one wrap on top of another — each wrap is a separate sterile barrier.'},
  {id:'304',question:'The government agency that regulates sterilization packaging materials is:',options:['EPA','FDA','CDC','OSHA'],correct_answer:1,domain:'Quality & Regulatory',difficulty:'easy',explanation:'The FDA regulates sterilization packaging as Class II medical devices.'},
  {id:'305',question:'Type of packaging containing no cellulosic materials used for low-temperature sterilization of small items is:',options:['Paper/plastic combinations','Muslin','Spunbond polyolefin-plastic combinations','Barrier cloth'],correct_answer:2,domain:'Packaging',difficulty:'hard',explanation:'Spunbond polyolefin (Tyvek) contains no cellulosic materials and is validated for low-temperature sterilization.'},
  {id:'306',question:'When using paper/plastic combination pouches package content information should be written on:',options:['The paper side','The plastic side','Either side','The label only'],correct_answer:1,domain:'Packaging',difficulty:'medium',explanation:'Package content information should be written on the plastic side — writing on paper can damage the barrier.'},
  {id:'307',question:'The wrapping technique most commonly used for small packs and most trays is:',options:['Square fold','Sequential flat wrap','Simultaneous flat wrap','Envelope fold'],correct_answer:3,domain:'Packaging',difficulty:'easy',explanation:'The envelope fold is the most commonly used wrapping technique for small packs and instrument trays.'},
  {id:'308',question:'Barrier packaging prevents microorganisms from entering packages and allows aseptic opening:',options:['True','False','Only for steam sterilization','Only for EO sterilization'],correct_answer:0,domain:'Packaging',difficulty:'easy',explanation:'Barrier packaging prevents microbial entry and allows aseptic presentation.'},
  {id:'309',question:'The process by which instruments are steam sterilized for immediate use is called:',options:['Emergency sterilization','Immediate use steam sterilization','Core sterilization','Rapid reprocessing'],correct_answer:1,domain:'Sterilization',difficulty:'easy',explanation:'IUSS (Immediate Use Steam Sterilization) is the correct term — flash sterilization is an outdated term.'},
  {id:'310',question:'Items to be disinfected or sterilized at the point of use must be:',options:['Properly cleaned per the manufacturer\'s IFU','Semi-critical devices','Non-critical devices','Heat sensitive'],correct_answer:0,domain:'Sterilization',difficulty:'medium',explanation:'Items for point-of-use processing must still be properly cleaned per manufacturer IFU.'},
  {id:'311',question:'The best way to transport IUSS items at the point of use is:',options:['Covered with a sterile towel','In a rigid container designed for IUSS','In a covered mesh-bottom tray','In a Kraft-paper bag'],correct_answer:1,domain:'Sterilization',difficulty:'medium',explanation:'A rigid container designed for IUSS provides the best protection during transport.'},
  {id:'312',question:'What is the length of time after sterilization that an IUSS item can be used?',options:['IUSS items must be used immediately','Up to 4 hours','Up to 8 hours','The next day'],correct_answer:0,domain:'Sterilization',difficulty:'easy',explanation:'IUSS items must be used immediately — they cannot be stored for later use.'},
  {id:'313',question:'Which statement about IUSS is true?',options:['It is the sterilization method of choice for metal instruments','It is recommended as a primary sterilization process by AAMI and AORN','It reduces turnaround time because cleaning is not required','It should only be used when there is not enough time to process items using the wrapped method'],correct_answer:3,domain:'Sterilization',difficulty:'medium',explanation:'IUSS should only be used when there is insufficient time for wrapped sterilization.'},
  {id:'314',question:'Both AORN and The Joint Commission recommend that:',options:['The use of IUSS be minimized or decreased','IUSS be performed in only one sterilizer per facility','Healthcare facilities receive clearance from the FDA for IUSS','Only SP technicians should operate immediate use steam sterilizers'],correct_answer:0,domain:'Sterilization',difficulty:'medium',explanation:'Both AORN and TJC recommend minimizing IUSS use.'},
  {id:'315',question:'Implantable devices should not be sterilized using IUSS unless:',options:['It is an emergency','A tracking system is in place to trace the item to the patient','The surgeon approves it','The device is metal'],correct_answer:1,domain:'Sterilization',difficulty:'hard',explanation:'Implants should not undergo IUSS unless a tracking system traces the item to the patient.'},
  {id:'316',question:'When transporting items that have undergone IUSS it is required that they be:',options:['Transported in a metal container','Transported to the patient area within five minutes of sterilization','Allowed to cool properly before transport','Transported in a way that reduces the potential for contamination'],correct_answer:3,domain:'Sterilization',difficulty:'medium',explanation:'IUSS items must be transported in a way that reduces contamination potential.'},
  {id:'317',question:'Terminal sterilization is:',options:['The process by which instruments are sterilized in their final containers allowing storage until needed','Process designed for cleaning and delivery of patient care items for immediate use','The process by which instruments are disinfected in their final containers','Process designed for cleaning disinfecting and delivery for immediate use'],correct_answer:0,domain:'Sterilization',difficulty:'medium',explanation:'Terminal sterilization packages items in their final sterile barrier allowing storage until point of use.'},
  {id:'318',question:'IUSS documentation should include:',options:['Patient ID','Sterilizer number and cycle','Name of the instrument sterilized','All the above'],correct_answer:3,domain:'Sterilization',difficulty:'easy',explanation:'IUSS documentation must include patient ID, sterilizer number and cycle, and instrument name.'},
  {id:'319',question:'Sterilization documentation IS required for items that undergo IUSS:',options:['True','False','Only for implants','Only for high-risk procedures'],correct_answer:0,domain:'Sterilization',difficulty:'medium',explanation:'Sterilization documentation is REQUIRED for all IUSS items.'},
  {id:'320',question:'IUSS was developed to process items when a facility does not have enough instrumentation:',options:['True','False — IUSS was developed to handle true emergency situations','Only in emergency departments','Only for orthopedic instruments'],correct_answer:1,domain:'Sterilization',difficulty:'hard',explanation:'IUSS was NOT developed to compensate for inadequate instrument inventory — it is for true emergencies only.'},
  {id:'321',question:'When loading a steam sterilizer basins should be:',options:['Placed in an upright position','Loaded first','Placed on edge','Placed in a wire basket'],correct_answer:2,domain:'Sterilization',difficulty:'medium',explanation:'Basins must be placed on edge and tilted to allow condensate to drain.'},
  {id:'322',question:'The higher the level of bioburden on an object the:',options:['More difficult it will be to sterilize','Less time it will take to sterilize','More biological tests will be needed in the load','Longer it will take to cool after sterilization'],correct_answer:0,domain:'Sterilization',difficulty:'medium',explanation:'Higher bioburden makes sterilization more difficult — soil protects microorganisms from sterilant contact.'},
  {id:'323',question:'When combining loads rigid containers should be placed on:',options:['The top shelf','The bottom shelf','The middle shelf','Any shelf'],correct_answer:1,domain:'Sterilization',difficulty:'hard',explanation:'Rigid containers go on the bottom shelf — textiles on top, pouches on edge.'},
  {id:'324',question:'SP technicians need to understand the anatomy of a steam sterilizer to:',options:['Know how to properly clean the chamber','Understand how the sterilizer operates','Understand how to test the thermostatic trap','All the above'],correct_answer:3,domain:'Sterilization',difficulty:'easy',explanation:'All three are important reasons — technicians must understand sterilizer anatomy for cleaning, operation, and testing.'},
  {id:'325',question:'The weakest part of a steam sterilizer is the:',options:['Jacket','Gasket','Door','Thermostatic valve'],correct_answer:1,domain:'Sterilization',difficulty:'medium',explanation:'The gasket is the weakest part — it is subject to wear and must be inspected regularly.'},
  {id:'326',question:'The three main phases of a terminal steam sterilizer cycle are:',options:['Gravity exposure and exhaust','Pre-vacuum exposure and exhaust','Exposure exhaust and dry','Conditioning exposure and exhaust'],correct_answer:3,domain:'Sterilization',difficulty:'hard',explanation:'The three phases are conditioning (air removal), exposure (sterilization), and exhaust (pressure release and drying).'},
  {id:'327',question:'The most common reason for steam sterilization failure is:',options:['Lack of steam contact with the contents of the load','Insufficient temperature in the sterilizer chamber','Inadequate exposure time','Drying issues'],correct_answer:0,domain:'Sterilization',difficulty:'medium',explanation:'Lack of steam contact is the most common cause — caused by improper loading, air pockets, or inadequate packaging.'},
  {id:'328',question:'The coolest area in a steam sterilizer is the:',options:['Gasket','Drain','Jacket','Chamber'],correct_answer:1,domain:'Sterilization',difficulty:'hard',explanation:'The drain is the coolest area — cool air and condensate drain from the bottom of the chamber.'},
  {id:'329',question:'Which is not part of the sterilizer physical monitor printout?',options:['Date and time the cycle began','Selected cycle parameters','Statement of guarantee of sterility','Written record of actual cycle activities'],correct_answer:2,domain:'Sterilization',difficulty:'hard',explanation:'A statement of guarantee of sterility is NOT on the printout — the printout records cycle data but cannot guarantee sterility.'},
  {id:'330',question:'One common cause of a clogged drain screen is:',options:['Tape','Wrapper particles','Poor steam quality','Malfunctioning baffle plate'],correct_answer:1,domain:'Sterilization',difficulty:'medium',explanation:'Wrapper particles are the most common cause of clogged drain screens.'},
  {id:'331',question:'For sterilization peel pouches should be placed:',options:['On edge paper to plastic','On edge plastic to plastic','Flat with the plastic side up','Flat with the paper side up'],correct_answer:0,domain:'Packaging',difficulty:'medium',explanation:'Peel pouches go on edge paper to plastic — this allows steam to enter through paper and air/condensate to exit through the drain.'},
  {id:'332',question:'Moisture can create a pathway for microorganisms to travel from the outside to inside of a package:',options:['True','False','Only for muslin wraps','Only for paper pouches'],correct_answer:0,domain:'Sterilization',difficulty:'medium',explanation:'Moisture creates a wicking pathway — wet packages allow microorganisms to travel from outside to inside.'},
  {id:'333',question:'How frequently should a sterilizer\'s chamber drain strainer be removed and cleaned?',options:['Daily','After each use','Once weekly','Only when indicated by the control gauge'],correct_answer:0,domain:'Sterilization',difficulty:'easy',explanation:'The drain strainer should be removed and cleaned daily to prevent buildup.'},
  {id:'334',question:'What is used daily to ensure air removal in pre-vacuum steam sterilizers?',options:['Infrared device','Bowie-Dick test','Humidity gauge','Sterilization parameter readout'],correct_answer:1,domain:'Sterilization',difficulty:'medium',explanation:'The Bowie-Dick test is run daily in pre-vacuum sterilizers to verify adequate air removal.'},
  {id:'335',question:'Which of the following can cause a wet pack?',options:['Placing dry instruments within a package','Heavy or dense instrument sets','Standing a basin on edge and tilting for drainage','Ensuring there is visible space between packs'],correct_answer:1,domain:'Sterilization',difficulty:'hard',explanation:'Heavy or dense instrument sets retain moisture during the drying cycle.'},
  {id:'336',question:'IUSS items cannot be stored — they must be used immediately:',options:['True','False','Only for implants','Only for Class III devices'],correct_answer:0,domain:'Sterilization',difficulty:'easy',explanation:'IUSS items have no sterile barrier packaging and must be used immediately after sterilization.'},
  {id:'337',question:'Placing warm sterilized packages on cool surfaces will cause:',options:['Biofilm formation','Wet packs from condensate','Package seal failure','CI color change reversal'],correct_answer:1,domain:'Sterilization',difficulty:'medium',explanation:'Condensate forms when warm packages contact cool surfaces — this creates wet packs that compromise the sterile barrier.'},
  {id:'338',question:'The thermostatic trap in a steam sterilizer:',options:['Heats the chamber walls','Seals the door','Measures steam temperature and controls flow of air and condensate','Contains the chamber drain'],correct_answer:2,domain:'Sterilization',difficulty:'hard',explanation:'The thermostatic trap measures temperature and automatically controls the flow of air and condensate.'},
  {id:'339',question:'Gravity displacement sterilizers remove air from the chamber by:',options:['Using a vacuum pump','Using steam to force cooler air out through the drain','Using filtered air exchanges','Using a thermostatic valve'],correct_answer:1,domain:'Sterilization',difficulty:'medium',explanation:'Gravity displacement sterilizers use steam to push heavier cool air downward and out through the chamber drain.'},
  {id:'340',question:'The most frequent cause for sterilization failure is lack of steam:',options:['Temperature','Contact','Pressure','Exposure time'],correct_answer:1,domain:'Sterilization',difficulty:'easy',explanation:'Lack of steam contact is the most frequent cause of sterilization failure.'},
  {id:'341',question:'Why is proper training for low-temperature sterilization important?',options:['Chemicals used have toxic properties','Technicians must know how to prevent instrument corrosion','Low-temperature sterilization is a costly process','Low-temperature methods are new technology with no standards'],correct_answer:0,domain:'Sterilization',difficulty:'easy',explanation:'The chemicals used in low-temperature sterilization are toxic — proper training is essential to protect staff.'},
  {id:'342',question:'When an item undergoes low-temperature sterilization what is meant by material compatibility?',options:['Two or more materials on the medical device interact','Two or more materials on the device do not interact','There should not be changes in the device\'s functionality','The manufacturer has validated the device is compatible with a specific low-temperature process'],correct_answer:3,domain:'Sterilization',difficulty:'hard',explanation:'Material compatibility means the manufacturer has validated the device is compatible with the specific sterilization process.'},
  {id:'343',question:'Which sterilization method can permeate throughout a wide range of materials to reach recessed areas?',options:['Hydrogen peroxide','Steam sterilization','Ethylene oxide','Glutaraldehyde'],correct_answer:2,domain:'Sterilization',difficulty:'hard',explanation:'Ethylene oxide gas permeates through a wide range of materials and packaging to reach recessed areas.'},
  {id:'344',question:'EO-sterilized items are aerated to remove residual:',options:['EO','Oxides','Peroxide','Alkali'],correct_answer:0,domain:'Sterilization',difficulty:'easy',explanation:'Aeration removes residual ethylene oxide gas from sterilized items — EO residue is toxic.'},
  {id:'345',question:'Which of the following items can be sterilized by H2O2?',options:['Antibiotics','Gauze sponges','Baby powder','Telescopes'],correct_answer:3,domain:'Sterilization',difficulty:'hard',explanation:'Telescopes can be sterilized by hydrogen peroxide — cellulosic materials like gauze and powders are not compatible.'},
  {id:'346',question:'Aeration instructions for a medical device can be found in/on the:',options:['Gas cartridge\'s IFU','Sterilizer\'s IFU','Device manufacturer\'s IFU','FDA\'s website'],correct_answer:2,domain:'Sterilization',difficulty:'medium',explanation:'Aeration instructions are found in the device manufacturer\'s IFU.'},
  {id:'347',question:'What is a permissible exposure limit (PEL)?',options:['The maximum time an item can undergo sterilization exposure','The maximum amount of sterilant an item can be exposed to','The maximum amount or concentration of a chemical a worker may be exposed to under OSHA regulations','The minimum and maximum time an employee can work with powder sterilization'],correct_answer:2,domain:'Safety',difficulty:'hard',explanation:'The PEL is the maximum chemical concentration a worker may be exposed to according to OSHA regulations.'},
  {id:'348',question:'Information about a device\'s compatibility with a specific sterilization process can be obtained:',options:['On the SDS','On the FDA\'s website','In AAMI standards','In the device\'s IFU'],correct_answer:3,domain:'Sterilization',difficulty:'medium',explanation:'Device compatibility with specific sterilization processes is found in the device manufacturer\'s IFU.'},
  {id:'349',question:'To ensure successful sterilization the sterilizer chamber should not be:',options:['Loaded a long time before sterilization','Overloaded','Underloaded','Loaded with mixed types of items'],correct_answer:1,domain:'Sterilization',difficulty:'easy',explanation:'Overloading is the primary loading error — it prevents adequate steam or sterilant penetration and contact.'},
  {id:'350',question:'PELs for low-temperature sterilization methods are established by the:',options:['FDA','CDC','OSHA','EPA'],correct_answer:2,domain:'Safety',difficulty:'medium',explanation:'OSHA establishes Permissible Exposure Limits (PELs) for chemical sterilants like EO and glutaraldehyde.'},
  {id:'351',question:'There should be at least how many air exchanges per hour in a room that has an EO sterilizer?',options:['4','6','10','12'],correct_answer:2,domain:'Sterilization',difficulty:'hard',explanation:'A minimum of 10 air exchanges per hour is required in rooms with EO sterilizers.'},
  {id:'352',question:'The probability of a viable microorganism being present on an item after sterilization is the:',options:['Sterility assurance level','Bioburden count','Spore log reduction','Minimum effective concentration'],correct_answer:0,domain:'Sterilization',difficulty:'hard',explanation:'Sterility assurance level (SAL) is the probability that a viable microorganism remains on an item after sterilization.'},
  {id:'353',question:'The bacterial spore used to test EO sterilization cycles is:',options:['Geobacillus stearothermophilus','Bacillus atrophaeus','Clostridium difficile','Staphylococcus aureus'],correct_answer:1,domain:'Sterilization',difficulty:'hard',explanation:'Bacillus atrophaeus is the biological indicator organism used to test EO sterilization cycles.'},
  {id:'354',question:'Geobacillus stearothermophilus is used to test:',options:['EO sterilization only','Steam sterilization and hydrogen peroxide sterilization','Low-temperature plasma only','Chemical sterilization only'],correct_answer:1,domain:'Sterilization',difficulty:'hard',explanation:'Geobacillus stearothermophilus is the biological indicator organism used to test both steam and H2O2 sterilization.'},
  {id:'355',question:'Personal monitoring for EO exposure requires the device to be affixed:',options:['To the employee\'s wrist','Directly to the employee\'s clothing in the breathing zone','Near the sterilizer','In the employee break room'],correct_answer:1,domain:'Safety',difficulty:'medium',explanation:'Personal monitoring devices must be worn in the breathing zone to accurately measure employee chemical exposure.'},
  {id:'356',question:'Satellite storage areas should:',options:['Be maintained by SP personnel','Be cleaned monthly','Follow the same guidelines used in SP storage','Only use closed shelving'],correct_answer:2,domain:'Sterile Storage',difficulty:'medium',explanation:'Satellite storage areas must follow the same storage guidelines as the main SP storage area.'},
  {id:'357',question:'Endoscopes that have undergone HLD should be stored:',options:['Completely dry','Within a clean wrapper','Hanging in an open cabinet','In a long plastic bag'],correct_answer:2,domain:'Endoscope Reprocessing',difficulty:'hard',explanation:'HLD endoscopes should be stored hanging in an open cabinet to allow continued drying.'},
  {id:'358',question:'How should sterile packages be arranged to allow for stock rotation?',options:['Take from the bottom first','Last in first out','First in first out','Last in last out'],correct_answer:2,domain:'Sterile Storage',difficulty:'easy',explanation:'FIFO (First In First Out) is the correct stock rotation method.'},
  {id:'359',question:'The sterile storage process begins:',options:['When items are received in the decontamination area','After items are sterilized and cooled','When the sterilizer door is opened at the end of a cycle','When items are placed inside the sterilizer'],correct_answer:1,domain:'Sterile Storage',difficulty:'medium',explanation:'Sterile storage begins after items are sterilized AND properly cooled.'},
  {id:'360',question:'Sterile storage areas should have:',options:['Positive airflow and at least 10 air exchanges per hour','Positive airflow and at least four air exchanges per hour','Negative airflow and at least 10 air exchanges per hour','Negative airflow and at least four air exchanges per hour'],correct_answer:0,domain:'Sterile Storage',difficulty:'hard',explanation:'Sterile storage must have positive airflow and at least 10 air exchanges per hour.'},
  {id:'361',question:'Following liquid chemical sterilization items intended to be used as critical devices may be stored for:',options:['No storage — they should be used immediately','60 minutes','Four hours','One day'],correct_answer:0,domain:'Sterilization',difficulty:'hard',explanation:'Items processed by LCS have no sterile barrier and must be used immediately.'},
  {id:'362',question:'The shelving system of choice for the sterile storage area is:',options:['Closed','Semi-closed','Open','Tracked'],correct_answer:0,domain:'Sterile Storage',difficulty:'easy',explanation:'Closed shelving is the preferred system for sterile storage.'},
  {id:'363',question:'Trays that overhang shelving:',options:['Can become contaminated','Are acceptable for rigid containers but not flat-wrapped trays','Are appropriate for heavy trays as they allow proper body mechanics','None of the above'],correct_answer:0,domain:'Sterile Storage',difficulty:'medium',explanation:'Trays overhanging shelving can become contaminated by air currents, touch, or contact with non-sterile surfaces.'},
  {id:'364',question:'The type of shelving that leaves packaging the most vulnerable is:',options:['Open','Closed','Semi-closed','Tracked'],correct_answer:0,domain:'Sterile Storage',difficulty:'easy',explanation:'Open shelving leaves packages most vulnerable to contamination from air, dust, and accidental contact.'},
  {id:'365',question:'The bottom shelf of any sterile storage system should be:',options:['Solid and eight to 10 inches from the floor','Solid and two to four inches from the floor','Made of wire and positioned two to four inches from the floor','Made of wire and positioned eight to 10 inches from the floor'],correct_answer:0,domain:'Sterile Storage',difficulty:'medium',explanation:'The bottom shelf must be solid and 8-10 inches from the floor.'},
  {id:'366',question:'Sterile trays should:',options:['Not be touched until they are properly cooled','Be lifted not dragged from the sterilizer cart','Be checked to confirm CIs have turned the appropriate color','All the above'],correct_answer:3,domain:'Sterile Storage',difficulty:'easy',explanation:'All three are correct — trays must cool completely, be lifted not dragged, and CIs must be verified.'},
  {id:'367',question:'Wrapped trays should not be stacked because:',options:['Tray contents may become damaged','It can cause holes in the wrappers','It will cause the shelving to bend','Trays will be more difficult to rotate'],correct_answer:1,domain:'Sterile Storage',difficulty:'medium',explanation:'Stacking wrapped trays causes holes in the wrappers compromising the sterile barrier.'},
  {id:'368',question:'Outside shipping containers should be removed before items enter sterile storage:',options:['True','False','Only for corrugated boxes','Only for items stored near in-house sterilized items'],correct_answer:0,domain:'Sterile Storage',difficulty:'easy',explanation:'Outside shipping containers must be removed — they are contaminated from transport.'},
  {id:'369',question:'How long can flexible endoscopes that have undergone HLD or LCS be stored?',options:['One week','One month','Six weeks','According to facility policy'],correct_answer:3,domain:'Sterile Storage',difficulty:'hard',explanation:'Storage time for HLD/LCS endoscopes is determined by facility policy based on storage conditions and packaging.'},
  {id:'370',question:'Items should be stored at least how many inches below sprinkler heads?',options:['8','12','18','24'],correct_answer:2,domain:'Sterile Storage',difficulty:'hard',explanation:'Items must be stored at least 18 inches below sprinkler heads to allow full sprinkler operation.'},
  {id:'371',question:'FIFO stands for:',options:['First In First Out','First In Final Out','Facility Inventory First Order','Final Inspection Final Output'],correct_answer:0,domain:'Sterile Storage',difficulty:'easy',explanation:'FIFO = First In First Out — the required stock rotation method ensuring older items are used before newer ones.'},
  {id:'372',question:'Airflow in the sterile storage area should be:',options:['Negative','Positive','Filtered only','No specific requirement'],correct_answer:1,domain:'Sterile Storage',difficulty:'medium',explanation:'Sterile storage must have positive airflow — this pushes any contaminants out rather than pulling them in.'},
  {id:'373',question:'Packaging that prevents microorganisms from entering packages and allows aseptic opening is called:',options:['Sterile wrap','Barrier packaging','Indicator packaging','Containment packaging'],correct_answer:1,domain:'Packaging',difficulty:'easy',explanation:'Barrier packaging prevents microbial entry and allows aseptic presentation.'},
  {id:'374',question:'Humidity in the sterile storage area should be:',options:['Less than 30%','30% to 60%','Greater than 60%','No specific requirement'],correct_answer:1,domain:'Sterile Storage',difficulty:'hard',explanation:'Humidity in sterile storage must be maintained at 30-60%.'},
  {id:'375',question:'Items should not be used after the manufacturer\'s expiration date even if the package integrity is still intact:',options:['True','False','Only for implants','Only for single-use devices'],correct_answer:0,domain:'Sterile Storage',difficulty:'easy',explanation:'Items must not be used after the manufacturer\'s expiration date regardless of package appearance.'},
  {id:'376',question:'Stacking wrapped trays can cause holes and other damage to wrappers:',options:['True','False','Only for muslin wraps','Only when trays are heavy'],correct_answer:0,domain:'Sterile Storage',difficulty:'easy',explanation:'Stacking wrapped trays creates pressure that can puncture or tear the sterile barrier.'},
  {id:'377',question:'When transporting sterile items in a dedicated clean lift they should be contained:',options:['True','False','Only for wrapped items','Only for rigid containers'],correct_answer:0,domain:'Sterile Storage',difficulty:'medium',explanation:'Sterile items must be contained even in a dedicated clean lift to protect them from contamination.'},
  {id:'378',question:'It is important to identify devices that have undergone HLD or LCS as patient-ready because:',options:['It prevents the need to reprocess if the HLD or LCS process is called into question','It helps identify each device\'s storage location','It distinguishes processed from non-processed devices','It documents who processed them last'],correct_answer:0,domain:'Sterilization',difficulty:'hard',explanation:'Identifying patient-ready devices allows targeted reprocessing if the disinfection process is questioned.'},
  {id:'379',question:'Horizontal work surfaces in the decontamination area should be cleaned and disinfected:',options:['Weekly','Monthly','Once per day','After each case'],correct_answer:2,domain:'Decontamination',difficulty:'easy',explanation:'Horizontal surfaces in decontamination must be cleaned and disinfected at least once per day.'},
  {id:'380',question:'To prevent aerosolization items should be brushed:',options:['Above the surface of the water','Below the surface of the water','In a dry container','Outside the sink'],correct_answer:1,domain:'Safety',difficulty:'easy',explanation:'Items must be brushed below the water surface to prevent aerosolization of potentially infectious particles.'},
  {id:'381',question:'Automatic washers clean using a spray-force action called:',options:['Cavitation','Aerosolization','Impingement','Emulsification'],correct_answer:2,domain:'Decontamination',difficulty:'medium',explanation:'Washer-disinfectors use impingement — a high-pressure spray-force action that removes soil from instrument surfaces.'},
  {id:'382',question:'PPE is required when using IUSS to clean items:',options:['True','False','Only for chemical sterilants','Only in the decontamination area'],correct_answer:0,domain:'Safety',difficulty:'easy',explanation:'PPE is always required when cleaning instruments regardless of whether they will undergo IUSS.'},
  {id:'383',question:'IUSS is NOT the sterilization method of choice for single-use items:',options:['True','False','Only for metal single-use items','Depends on the device'],correct_answer:0,domain:'Sterilization',difficulty:'medium',explanation:'IUSS is not appropriate for single-use devices. Single-use items should not be reprocessed.'},
  {id:'384',question:'Following a procedure on a patient with confirmed CJD IUSS is NOT recommended:',options:['True','False','Only if instruments are visibly contaminated','Only for implants used in the procedure'],correct_answer:0,domain:'Sterilization',difficulty:'hard',explanation:'IUSS is not recommended for CJD cases. Special decontamination protocols are required for prion disease instruments.'},
  {id:'385',question:'The manufacturer\'s IFU must state a device can be sterilized using IUSS before it is processed that way:',options:['True','False','Only for implants','Only for powered instruments'],correct_answer:0,domain:'Sterilization',difficulty:'hard',explanation:'The manufacturer\'s IFU must validate IUSS compatibility. If the IFU does not mention IUSS the device cannot be processed that way.'},
  {id:'386',question:'All items sterilized or HLD at point of use must be carefully monitored and documented:',options:['True','False','Only for implants','Only for reusable devices'],correct_answer:0,domain:'Sterilization',difficulty:'easy',explanation:'All point-of-use sterilization and HLD must be monitored and documented for patient traceability.'},
  {id:'387',question:'The interior chamber walls of a sterilizer are heated by steam in the:',options:['Gasket','Jacket','Chamber drain','Thermostatic trap'],correct_answer:1,domain:'Sterilization',difficulty:'medium',explanation:'The jacket of the sterilizer heats the chamber walls — this pre-heating reduces condensation.'},
  {id:'388',question:'The chamber drain is located in the floor of the steam sterilizer:',options:['True','False','Only in gravity sterilizers','Only in pre-vacuum sterilizers'],correct_answer:0,domain:'Sterilization',difficulty:'medium',explanation:'The chamber drain is located in the floor of the sterilizer — air and condensate drain downward by gravity.'},
  {id:'389',question:'Charts and printouts provide a written record of sterilizer cycle activities:',options:['True','False','Only for pre-vacuum sterilizers','Only for steam sterilizers'],correct_answer:0,domain:'Sterilization',difficulty:'easy',explanation:'Charts and printouts are the physical monitors that provide a written record of actual sterilizer cycle activities.'},
  {id:'390',question:'Why is it important to document wet packs?',options:['To identify when it will be safe to unload the sterilizer cart','Because it is required by HHS','Because it is required in the instrument tracking system','Because of the complexity of the issue'],correct_answer:2,domain:'Sterilization',difficulty:'hard',explanation:'Wet pack documentation is required in the instrument tracking system so affected items can be identified.'},
  {id:'391',question:'OSHA sets exposure standards for chemical sterilants:',options:['True','False','Only for EO','Only for glutaraldehyde'],correct_answer:0,domain:'Safety',difficulty:'easy',explanation:'OSHA establishes Permissible Exposure Limits (PELs) for chemical sterilants including EO and glutaraldehyde.'},
  {id:'392',question:'The aeration phase of an EO sterilizer cycle immediately follows the sterilization phase:',options:['True','False','Only for 100% EO','Only for mixed gas EO'],correct_answer:0,domain:'Sterilization',difficulty:'medium',explanation:'Aeration immediately follows sterilization in an EO cycle to begin removing toxic residual gas.'},
  {id:'393',question:'The method of stock rotation that ensures older items are used first is called:',options:['LIFO','FIFO','FILO','LILO'],correct_answer:1,domain:'Sterile Storage',difficulty:'easy',explanation:'FIFO (First In First Out) is the required stock rotation method.'},
  {id:'394',question:'Because they are mild cleaners dish soaps are the cleaners of choice for surgical instruments:',options:['True','False','Only for delicate instruments','Only for stainless steel'],correct_answer:1,domain:'Decontamination',difficulty:'medium',explanation:'False — dish soaps are NOT appropriate for surgical instruments. They may leave residue and cause corrosion.'},
  {id:'395',question:'There is no need to pre-clean items that will be processed in an ultrasonic cleaner:',options:['True','False — pre-cleaning is required','Only for heavily soiled items','Only for powered instruments'],correct_answer:1,domain:'Decontamination',difficulty:'medium',explanation:'Pre-cleaning IS required before ultrasonic cleaning — gross soil must be removed first.'},
  {id:'396',question:'Instruments received from surgery and tagged for repair do not need to be cleaned until they come back from repair:',options:['True','False — they must be cleaned before being sent for repair','Only if visibly soiled','Only for powered instruments'],correct_answer:1,domain:'Decontamination',difficulty:'hard',explanation:'Instruments tagged for repair must be cleaned before being sent — repair technicians should not handle contaminated instruments.'},
  {id:'397',question:'Powered surgical instruments should be cleaned using a mechanical cleaning process:',options:['True','False — powered surgical instruments cannot be mechanically cleaned','Only if manufacturer approves','Only for electric instruments'],correct_answer:2,domain:'Decontamination',difficulty:'hard',explanation:'Powered surgical instruments may only be mechanically cleaned if the manufacturer\'s IFU approves it.'},
  {id:'398',question:'Laparoscopic instrument insulation failure can cause burns to the patient:',options:['True','False','Only during monopolar cautery','Only if insulation is completely missing'],correct_answer:0,domain:'Endoscope Reprocessing',difficulty:'medium',explanation:'Insulation failure on laparoscopic instruments can cause burns to the patient from stray electrical current during surgery.'},
  {id:'399',question:'The purpose of a decontamination battery or hose is to protect powered instruments from fluid invasion during cleaning:',options:['True','False','Only for battery-powered instruments','Only for pneumatic instruments'],correct_answer:0,domain:'Decontamination',difficulty:'easy',explanation:'A decontamination battery or hose protects powered instruments from fluid invasion during the cleaning process.'},
  {id:'400',question:'A disadvantage of rigid sterilization containers is:',options:['Their barrier qualities','They help eliminate torn wrappers','They help protect instruments during processing storage and transport','Additional cycle time may be required to thoroughly dry the contents'],correct_answer:3,domain:'Packaging',difficulty:'medium',explanation:'Rigid containers require additional drying time — this is their primary disadvantage compared to wrapped packages.'}
]
